import React, { useEffect, useState, useMemo } from "react";
import { MessageSquare } from "lucide-react";
import { cn } from "../lib/utils.js";
import { ChatProvider, useChatContext } from "../hooks/ChatProvider.js";
import { MessageList } from "./MessageList.js";
import { MessageInput } from "./MessageInput.js";
import { ModelSelect } from "./ModelSelect.js";
import { LocaleSelect } from "./LocaleSelect.js";
import { useModels } from "../hooks/useModels.js";
import { LocaleProvider, useTranslation, resolveLocale } from "../i18n/index.js";
import type { CustomMessages, CustomLocaleInfo } from "../i18n/index.js";
import type { DisplayRendererMap } from "../display/registry.js";
import type { Message } from "../types.js";

// Literal classes so Tailwind's source scanner picks them all up at build time.
const MAX_WIDTH_CLASS = {
  sm: "max-w-sm",
  md: "max-w-md",
  lg: "max-w-lg",
  xl: "max-w-xl",
  "2xl": "max-w-2xl",
  "3xl": "max-w-3xl",
  "4xl": "max-w-4xl",
  "5xl": "max-w-5xl",
  "6xl": "max-w-6xl",
  "7xl": "max-w-7xl",
} as const;

export type ChatMaxWidth = keyof typeof MAX_WIDTH_CLASS | false;

export interface ChatProps {
  /** Base URL do servico openclaude (ex: http://localhost:9500/api/v1/ai). */
  endpoint: string;
  token?: string;
  /** Sessao live existente. Se omitida, o hook cria uma via POST /conversations. */
  sessionId?: string;
  initialMessages?: Message[];
  sessionOptions?: Record<string, unknown>;
  turnOptions?: Record<string, unknown>;
  displayRenderers?: DisplayRendererMap;
  placeholder?: string;
  header?: React.ReactNode;
  footer?: React.ReactNode;
  className?: string;
  enableAttachments?: boolean;
  enableVoice?: boolean;
  /** Mostra combo de selecao de modelo (carregado via GET /models). */
  enableModelSelect?: boolean;
  /** Mostra seletor de locale no bottomSlot do input. Default: true. */
  enableLocaleSelect?: boolean;
  /** Locale inicial (aceita "pt-BR", "pt_br", "pt", etc). Default: "en-US". */
  locale?: string;
  /** Callback quando o usuario troca o locale via selector. */
  onLocaleChange?: (locale: string) => void;
  /** Translation overrides keyed by locale slug. */
  messages?: CustomMessages;
  /** Metadata for custom locales (shown in locale selector). */
  locales?: CustomLocaleInfo;
  fetcher?: typeof fetch;
  emptyState?: React.ReactNode;
  /**
   * Max-width do conteudo do chat (mensagens + input). O chat se centraliza
   * horizontalmente dentro de um wrapper interno com esse limite. Passar
   * `false` desativa o limite e o chat ocupa 100% da largura disponivel.
   * Default: "3xl".
   */
  maxWidth?: ChatMaxWidth;
}

interface ChatContentProps {
  displayRenderers?: DisplayRendererMap;
  placeholder?: string;
  enableAttachments?: boolean;
  enableVoice?: boolean;
  emptyState?: React.ReactNode;
  bottomSlot?: React.ReactNode;
}

function NoSessionState({ children }: { children?: React.ReactNode }) {
  const { t } = useTranslation();
  return children ? (
    <>{children}</>
  ) : (
    <div className="flex h-full flex-col items-center justify-center gap-4 px-6 py-16 text-center">
      <div className="flex size-14 items-center justify-center rounded-2xl bg-primary/10 text-primary ring-1 ring-primary/20">
        <MessageSquare className="size-7" />
      </div>
      <div className="space-y-1.5">
        <h2 className="text-xl font-semibold tracking-tight">{t("chat.selectConversation")}</h2>
        <p className="max-w-sm text-sm text-muted-foreground">
          {t("chat.orCreateNew")}
        </p>
      </div>
    </div>
  );
}

function ChatContent({ displayRenderers, placeholder, enableAttachments = true, enableVoice = true, emptyState, bottomSlot }: ChatContentProps) {
  const { messages, input, setInput, handleSubmit, isLoading, stop, error, reload } = useChatContext();

  return (
    <>
      <MessageList
        messages={messages}
        isLoading={isLoading}
        displayRenderers={displayRenderers}
        error={error ?? undefined}
        onRetry={reload}
        emptyState={emptyState}
      />
      <div className="px-4 pb-4">
        <MessageInput
          input={input}
          setInput={setInput}
          handleSubmit={handleSubmit}
          isLoading={isLoading}
          stop={stop}
          placeholder={placeholder}
          enableAttachments={enableAttachments}
          enableVoice={enableVoice}
          bottomSlot={bottomSlot}
        />
      </div>
    </>
  );
}

export function Chat({
  endpoint,
  token,
  sessionId,
  initialMessages,
  sessionOptions,
  turnOptions,
  displayRenderers,
  placeholder,
  header,
  footer,
  className,
  enableAttachments,
  enableVoice,
  enableModelSelect,
  enableLocaleSelect = true,
  locale: localeProp,
  onLocaleChange,
  messages: messagesProp,
  locales: localesProp,
  fetcher,
  emptyState,
  maxWidth = "3xl",
}: ChatProps) {
  const { models, defaultModel, isLoading: modelsLoading } = useModels(
    enableModelSelect ? endpoint : "",
    enableModelSelect ? fetcher : undefined,
  );
  const [selectedModel, setSelectedModel] = useState<string | undefined>(undefined);
  const resolvedLocale = useMemo(() => resolveLocale(localeProp), [localeProp]);
  const [currentLocale, setCurrentLocale] = useState(resolvedLocale);

  // Sync internal state when parent changes locale prop (e.g. via ChatHeader)
  useEffect(() => {
    setCurrentLocale(resolvedLocale);
  }, [resolvedLocale]);

  const handleLocaleChange = (l: string) => {
    setCurrentLocale(l);
    onLocaleChange?.(l);
  };

  // Resolve o modelo efetivo: selecionado pelo usuario ou default do catalogo
  const effectiveModel = enableModelSelect
    ? selectedModel ?? defaultModel ?? undefined
    : undefined;

  // Memoiza sessionOptions para evitar re-render infinito quando model muda
  const mergedSessionOptions = useMemo(
    () => sessionOptions,
    [sessionOptions],
  );

  const outerClass = cn(
    "flex flex-col flex-1 min-h-0 h-full bg-background text-foreground",
    maxWidth !== false && "items-center",
    className,
  );
  const innerClass = cn(
    "flex flex-col flex-1 min-h-0 w-full",
    maxWidth !== false && MAX_WIDTH_CLASS[maxWidth],
  );

  const hasBottomSlotContent = enableLocaleSelect || enableModelSelect;
  const bottomSlot = hasBottomSlotContent ? (
    <div className="flex items-center gap-1">
      {enableLocaleSelect && (
        <LocaleSelect value={currentLocale} onChange={handleLocaleChange} />
      )}
      {enableModelSelect && (
        <ModelSelect
          models={models}
          value={selectedModel ?? defaultModel ?? (models[0]?.id ?? "")}
          onChange={setSelectedModel}
          isLoading={modelsLoading}
        />
      )}
    </div>
  ) : undefined;

  if (!sessionId) {
    return (
      <LocaleProvider locale={currentLocale} messages={messagesProp} locales={localesProp}>
        <div className={outerClass}>
          <div className={innerClass}>
            {header}
            <NoSessionState>{emptyState}</NoSessionState>
            {footer}
          </div>
        </div>
      </LocaleProvider>
    );
  }

  return (
    <LocaleProvider locale={currentLocale} messages={messagesProp} locales={localesProp}>
      <ChatProvider
        key={sessionId}
        endpoint={endpoint}
        token={token}
        sessionId={sessionId}
        initialMessages={initialMessages}
        sessionOptions={mergedSessionOptions}
        turnOptions={turnOptions}
        model={effectiveModel}
        fetcher={fetcher}
      >
        <div className={outerClass}>
          <div className={innerClass}>
            {header}
            <ChatContent
              displayRenderers={displayRenderers}
              placeholder={placeholder}
              enableAttachments={enableAttachments}
              enableVoice={enableVoice}
              emptyState={emptyState}
              bottomSlot={bottomSlot}
            />
            {footer}
          </div>
        </div>
      </ChatProvider>
    </LocaleProvider>
  );
}

import React, { useCallback, useEffect, useRef, useState } from "react";
import { MoreHorizontal, Pencil, Star, StarOff } from "lucide-react";
import { cn } from "../lib/utils.js";
import { Button } from "../ui/button.js";
import { LocaleSelect } from "./LocaleSelect.js";
import { useTranslation } from "../i18n/index.js";
import { Tooltip, TooltipContent, TooltipTrigger, TooltipProvider } from "../ui/tooltip.js";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "../ui/dropdown-menu.js";

export interface ChatHeaderProps {
  /** Slot rendered at the far left, before star/title. Use for sidebar toggle, etc. */
  leftContent?: React.ReactNode;
  /** Conversation title. When undefined, session-dependent elements are hidden. */
  title?: string;
  /** Whether the conversation is starred/bookmarked. */
  starred?: boolean;
  /** Called when user toggles the star. */
  onToggleStar?: () => void;
  /** Called when user renames the conversation. */
  onRename?: (title: string) => void;
  /** Show agent avatar+name instead of star+title. */
  showAgent?: boolean;
  /** Agent avatar URL. Only used when showAgent=true. */
  agentAvatar?: string;
  /** Agent display name. Only used when showAgent=true. */
  agentName?: string;
  /** Current locale slug. */
  locale?: string;
  /** Called when user changes locale. */
  onLocaleChange?: (locale: string) => void;
  /** Show locale selector. Mirrors the Chat component flag. */
  enableLocaleSelect?: boolean;
  className?: string;
}

export function ChatHeader({
  leftContent,
  title,
  starred,
  onToggleStar,
  onRename,
  showAgent,
  agentAvatar,
  agentName,
  locale,
  onLocaleChange,
  enableLocaleSelect = true,
  className,
}: ChatHeaderProps) {
  const { t } = useTranslation();
  const hasSession = title !== undefined;
  const [isRenaming, setIsRenaming] = useState(false);
  const [draft, setDraft] = useState(title ?? "");
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (isRenaming) {
      setDraft(title ?? "");
      const timer = setTimeout(() => {
        inputRef.current?.focus();
        inputRef.current?.select();
      }, 0);
      return () => clearTimeout(timer);
    }
  }, [isRenaming, title]);

  const commitRename = useCallback(() => {
    const trimmed = draft.trim();
    if (trimmed && trimmed !== title) {
      onRename?.(trimmed);
    }
    setIsRenaming(false);
  }, [draft, title, onRename]);

  const cancelRename = useCallback(() => {
    setDraft(title ?? "");
    setIsRenaming(false);
  }, [title]);

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (e.key === "Enter") {
        e.preventDefault();
        commitRename();
      } else if (e.key === "Escape") {
        e.preventDefault();
        cancelRename();
      }
    },
    [commitRename, cancelRename],
  );

  return (
    <TooltipProvider delayDuration={300}>
      <div
        className={cn(
          "flex h-14 shrink-0 items-center justify-between border-b px-3",
          className,
        )}
      >
        {/* Left: leftContent slot + star/title or agent avatar */}
        <div className="flex min-w-0 items-center gap-1.5">
          {leftContent}
          {hasSession && showAgent ? (
            <>
              {agentAvatar && (
                <img
                  src={agentAvatar}
                  alt={agentName ?? "Agent"}
                  className="h-6 w-6 shrink-0 rounded-full"
                />
              )}
              {agentName && (
                <span className="truncate text-sm font-medium">{agentName}</span>
              )}
            </>
          ) : hasSession ? (
            <>
              <Tooltip>
                <TooltipTrigger asChild>
                  <Button
                    variant="ghost"
                    size="icon"
                    className="h-8 w-8 shrink-0"
                    onClick={onToggleStar}
                  >
                    <Star
                      className={cn(
                        "h-4 w-4",
                        starred
                          ? "fill-yellow-400 text-yellow-400"
                          : "text-muted-foreground",
                      )}
                    />
                  </Button>
                </TooltipTrigger>
                <TooltipContent side="bottom">
                  {starred ? t("history.unfavorite") : t("history.favorite")}
                </TooltipContent>
              </Tooltip>
              {isRenaming ? (
                <input
                  ref={inputRef}
                  value={draft}
                  onChange={(e) => setDraft(e.target.value)}
                  onBlur={commitRename}
                  onKeyDown={handleKeyDown}
                  className="min-w-0 flex-1 rounded border border-input bg-background px-1.5 py-0.5 text-sm outline-none focus-visible:ring-1 focus-visible:ring-ring"
                />
              ) : (
                <span className="truncate text-sm font-medium">{title}</span>
              )}
            </>
          ) : (
            leftContent && null
          )}
        </div>

        {/* Right: locale selector + menu */}
        <div className="flex shrink-0 items-center gap-0.5">
          {enableLocaleSelect && locale && onLocaleChange && (
            <LocaleSelect value={locale} onChange={onLocaleChange} />
          )}
          {hasSession && !isRenaming && (
            <DropdownMenu>
              <DropdownMenuTrigger asChild>
                <Button variant="ghost" size="icon" className="h-8 w-8">
                  <MoreHorizontal className="h-4 w-4 text-muted-foreground" />
                </Button>
              </DropdownMenuTrigger>
              <DropdownMenuContent align="end" className="w-48">
                <DropdownMenuItem onClick={() => setIsRenaming(true)}>
                  <Pencil className="mr-2 h-4 w-4" />
                  {t("history.rename")}
                </DropdownMenuItem>
                <DropdownMenuItem onClick={onToggleStar}>
                  {starred ? (
                    <>
                      <StarOff className="mr-2 h-4 w-4" />
                      {t("history.unfavorite")}
                    </>
                  ) : (
                    <>
                      <Star className="mr-2 h-4 w-4" />
                      {t("history.favorite")}
                    </>
                  )}
                </DropdownMenuItem>
              </DropdownMenuContent>
            </DropdownMenu>
          )}
        </div>
      </div>
    </TooltipProvider>
  );
}

import { AlertTriangle, RotateCcw } from "lucide-react";
import { cn } from "../lib/utils.js";
import { useTranslation } from "../i18n/index.js";

export interface ErrorNoteProps {
  message?: string;
  onRetry?: () => void;
  className?: string;
}

export function ErrorNote({ message, onRetry, className }: ErrorNoteProps) {
  const { t } = useTranslation();
  return (
    <div
      role="alert"
      className={cn(
        "flex items-start gap-2 rounded-lg border border-destructive/30 bg-destructive/5 px-3 py-2 text-sm text-destructive",
        className
      )}
    >
      <AlertTriangle className="size-4 shrink-0 mt-0.5" />
      <span className="flex-1 min-w-0 break-words">
        {message ?? t("error.default")}
      </span>
      {onRetry && (
        <button
          type="button"
          onClick={onRetry}
          className="shrink-0 inline-flex items-center gap-1.5 rounded-md px-2 py-1 text-xs font-medium text-destructive hover:bg-destructive/10 transition-colors"
        >
          <RotateCcw className="size-3.5" />
          {t("error.retry")}
        </button>
      )}
    </div>
  );
}

import React, { useCallback, useMemo, useState } from "react"
import { MessageSquarePlus } from "lucide-react"
import { cn } from "../lib/utils.js"
import { TooltipProvider } from "../ui/tooltip.js"
import { Button } from "../ui/button.js"
import { Separator } from "../ui/separator.js"
import { ScrollArea } from "../ui/scroll-area.js"
import { HistorySearch } from "./history/HistorySearch.js"
import { HistoryGroup } from "./history/HistoryGroup.js"
import { HistoryDeleteDialog } from "./history/HistoryDeleteDialog.js"
import { useHistoryData, createLocalStorageTransport } from "./history/useHistoryData.js"
import { createDefaultTransport, type ChatTransport } from "../transport.js"
import { useHistoryContext } from "../hooks/HistoryProvider.js"
import { LocaleProvider, useTranslation, resolveLocale } from "../i18n/index.js"
import type { CustomMessages, CustomLocaleInfo } from "../i18n/index.js"

export interface HistoryProps {
  /** Base URL for the default transport. Ignored if `transport` is provided. */
  endpoint?: string
  /** Bearer token for the default transport. Ignored if `transport` is provided. */
  token?: string
  /** Custom transport — overrides endpoint/token. */
  transport?: ChatTransport
  /** Currently active conversation id. */
  activeConversationId?: string | null
  /** Called when user selects a conversation. */
  onSelectConversation?: (id: string) => void
  /** Called when user creates a new conversation. Receives the new session id. */
  onNewConversation?: (id: string) => void
  /** Called after a conversation is deleted. */
  onDeleteConversation?: (id: string) => void
  /** Locale for UI strings (accepts "pt-BR", "pt_br", "pt", etc). */
  locale?: string
  /** Translation overrides keyed by locale slug. */
  messages?: CustomMessages
  /** Metadata for custom locales. */
  locales?: CustomLocaleInfo
  /** When defined, History is controlled by the host. Hides the internal search input. */
  searchQuery?: string
  /** Called when the internal input changes (uncontrolled) or proxies external changes (controlled). */
  onSearchChange?: (q: string) => void
  /** Hide the internal search input even when uncontrolled (host renders its own input elsewhere). */
  hideSearchInput?: boolean
  className?: string
}

/** Wrapper that provides LocaleProvider, then renders the content. */
export function History({ locale: localeProp, messages, locales, ...rest }: HistoryProps) {
  const resolvedLocale = resolveLocale(localeProp)
  return (
    <LocaleProvider locale={resolvedLocale} messages={messages} locales={locales}>
      <HistoryContent {...rest} />
    </LocaleProvider>
  )
}

function HistoryContent({
  endpoint,
  token,
  transport: customTransport,
  activeConversationId = null,
  onSelectConversation,
  onNewConversation,
  onDeleteConversation,
  searchQuery: externalSearchQuery,
  onSearchChange,
  hideSearchInput,
  className,
}: Omit<HistoryProps, "locale">) {
  const { t } = useTranslation()

  // Resolve transport: custom > default (endpoint) > localStorage mock
  const transport = useMemo(() => {
    if (customTransport) {
      if (endpoint) {
        console.warn(
          "[openclaude-chat] History: both `transport` and `endpoint` were provided. " +
          "`endpoint` and `token` are ignored when `transport` is set.",
        )
      }
      return customTransport
    }
    if (endpoint) return createDefaultTransport(endpoint, token)
    return createLocalStorageTransport()
  }, [customTransport, endpoint, token])

  // Try to read agentId and registerRefresh from HistoryProvider context (if available)
  let ctxAgentId: string | undefined
  let ctxRegisterRefresh: ((fn: () => Promise<void>) => void) | undefined
  try {
    // eslint-disable-next-line react-hooks/rules-of-hooks
    const ctx = useHistoryContext()
    ctxAgentId = ctx.agentId
    ctxRegisterRefresh = ctx.registerRefresh
  } catch {
    // Not inside HistoryProvider — that's fine, agentId stays undefined
  }

  const {
    filteredGroups,
    searchQuery,
    setSearchQuery,
    isLoading,
    createConversation,
    renameConversation,
    deleteConversation,
    toggleStar,
  } = useHistoryData(transport, {
    agentId: ctxAgentId,
    registerRefresh: ctxRegisterRefresh,
    externalSearchQuery,
    onExternalSearchChange: onSearchChange,
  })

  const isSearchControlled = externalSearchQuery !== undefined
  const showInternalSearch = !hideSearchInput && !isSearchControlled

  // Delete confirmation state
  const [deleteTarget, setDeleteTarget] = useState<{ id: string; title: string } | null>(null)

  const handleNew = useCallback(async () => {
    const sessionId = await createConversation()
    onNewConversation?.(sessionId)
    onSelectConversation?.(sessionId)
  }, [createConversation, onNewConversation, onSelectConversation])

  const handleSelect = useCallback(
    (id: string) => onSelectConversation?.(id),
    [onSelectConversation],
  )

  const handleDeleteRequest = useCallback(
    (id: string) => {
      for (const g of filteredGroups) {
        const c = g.conversations.find((x) => x.id === id)
        if (c) {
          setDeleteTarget({ id, title: c.title })
          return
        }
      }
    },
    [filteredGroups],
  )

  const handleDeleteConfirm = useCallback(async () => {
    if (!deleteTarget) return
    await deleteConversation(deleteTarget.id)
    onDeleteConversation?.(deleteTarget.id)
    setDeleteTarget(null)
  }, [deleteTarget, deleteConversation, onDeleteConversation])

  const handleDeleteCancel = useCallback(() => setDeleteTarget(null), [])

  return (
    <TooltipProvider delayDuration={300}>
      <div className={cn("flex h-full w-[280px] flex-col border-r bg-background", className)}>
        {/* Header */}
        <div className="flex h-14 shrink-0 items-center justify-between px-3">
          <span className="text-sm font-semibold">{t("history.title")}</span>
          <Button variant="ghost" size="icon" className="h-8 w-8" onClick={handleNew}>
            <MessageSquarePlus className="h-4 w-4" />
          </Button>
        </div>

        <Separator />

        {/* Search */}
        {showInternalSearch && (
          <>
            <div className="shrink-0 py-2">
              <HistorySearch value={searchQuery} onChange={setSearchQuery} />
            </div>
            <Separator />
          </>
        )}

        {/* List */}
        <ScrollArea className="flex-1">
          <div className="flex flex-col gap-2 p-1.5">
            {isLoading && filteredGroups.length === 0 && (
              <div className="px-3 py-8 text-center text-xs text-muted-foreground">
                {t("history.loading")}
              </div>
            )}

            {!isLoading && filteredGroups.length === 0 && (
              <div className="px-3 py-8 text-center text-xs text-muted-foreground">
                {searchQuery ? t("history.noResults") : t("history.empty")}
              </div>
            )}

            {filteredGroups.map((group) => (
              <HistoryGroup
                key={group.label}
                group={group}
                activeId={activeConversationId}
                onSelect={handleSelect}
                onRename={renameConversation}
                onDelete={handleDeleteRequest}
                onToggleStar={toggleStar}
              />
            ))}
          </div>
        </ScrollArea>

        {/* Delete confirmation */}
        <HistoryDeleteDialog
          open={deleteTarget !== null}
          title={deleteTarget?.title ?? ""}
          onConfirm={handleDeleteConfirm}
          onCancel={handleDeleteCancel}
        />
      </div>
    </TooltipProvider>
  )
}

import React from "react"
import { PanelLeft, PanelLeftClose } from "lucide-react"
import { Button } from "../ui/button.js"
import { useHistoryContext } from "../hooks/HistoryProvider.js"

export interface HistoryTriggerProps {
  className?: string
}

/**
 * Button that toggles the sidebar open/close state via HistoryProvider context.
 * Place inside a HistoryProvider, typically in the ChatHeader's leftContent slot.
 */
export function HistoryTrigger({ className }: HistoryTriggerProps) {
  const { sidebarOpen, setSidebarOpen } = useHistoryContext()

  return (
    <Button
      variant="ghost"
      size="icon"
      className={className ?? "h-8 w-8 shrink-0"}
      onClick={() => setSidebarOpen(!sidebarOpen)}
    >
      {sidebarOpen ? (
        <PanelLeftClose className="h-4 w-4" />
      ) : (
        <PanelLeft className="h-4 w-4" />
      )}
    </Button>
  )
}

import { useRef, useState, useEffect, type ReactNode } from "react";

interface LazyRenderProps {
  children: ReactNode;
  minHeight?: number;
  rootMargin?: string;
}

export function LazyRender({ children, minHeight = 120, rootMargin = "200px" }: LazyRenderProps) {
  const ref = useRef<HTMLDivElement>(null);
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;

    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setVisible(true);
          observer.disconnect();
        }
      },
      { rootMargin }
    );

    observer.observe(el);
    return () => observer.disconnect();
  }, [rootMargin]);

  if (visible) return <>{children}</>;

  return (
    <div
      ref={ref}
      className="flex items-center justify-center text-muted-foreground text-xs rounded-md bg-muted/20 animate-pulse"
      style={{ minHeight }}
    >
      Carregando...
    </div>
  );
}

import React from "react";
import { Check } from "lucide-react";
import { cn } from "../lib/utils.js";
import { Button } from "../ui/button.js";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "../ui/dropdown-menu.js";
import { useTranslation } from "../i18n/index.js";

export interface LocaleSelectProps {
  value: string;
  onChange: (locale: string) => void;
  className?: string;
}

export function LocaleSelect({ value, onChange, className }: LocaleSelectProps) {
  const { supportedLocales } = useTranslation();
  const current = supportedLocales.find((l) => l.slug === value);

  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <Button variant="ghost" size="sm" className={cn("gap-1 text-xs font-normal px-2", className)}>
          <span className="text-base leading-none">{current?.flag}</span>
        </Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent align="start">
        {supportedLocales.map((l) => (
          <DropdownMenuItem
            key={l.slug}
            onSelect={() => onChange(l.slug)}
            className="gap-2 text-xs"
          >
            <Check className={cn("size-3", l.slug === value ? "opacity-100" : "opacity-0")} />
            <span className="text-base leading-none">{l.flag}</span>
            {l.name}
          </DropdownMenuItem>
        ))}
      </DropdownMenuContent>
    </DropdownMenu>
  );
}

import { memo } from "react";
import ReactMarkdown from "react-markdown";
import remarkGfm from "remark-gfm";
import rehypeHighlight from "rehype-highlight";
import type { Components } from "react-markdown";
import { cn } from "../lib/utils.js";

const REMARK_PLUGINS = [remarkGfm];
const REHYPE_PLUGINS = [rehypeHighlight];

const components: Components = {
  h1({ children }) {
    return <h1 className="text-xl font-semibold" style={{ marginTop: "20px", marginBottom: "8px" }}>{children}</h1>;
  },
  h2({ children }) {
    return <h2 className="text-lg font-semibold" style={{ marginTop: "20px", marginBottom: "8px" }}>{children}</h2>;
  },
  h3({ children }) {
    return <h3 className="text-base font-semibold" style={{ marginTop: "20px", marginBottom: "8px" }}>{children}</h3>;
  },
  h4({ children }) {
    return <h4 className="font-semibold" style={{ marginTop: "20px", marginBottom: "8px" }}>{children}</h4>;
  },
  p({ children }) {
    return <p className="mb-4 last:mb-0">{children}</p>;
  },
  ul({ children }) {
    return <ul style={{ paddingLeft: "24px", marginTop: "8px", marginBottom: "8px", listStyleType: "disc" }}>{children}</ul>;
  },
  ol({ children }) {
    return <ol style={{ paddingLeft: "24px", marginTop: "8px", marginBottom: "8px", listStyleType: "decimal" }}>{children}</ol>;
  },
  li({ children }) {
    return <li style={{ marginTop: "4px", marginBottom: "4px" }}>{children}</li>;
  },
  hr() {
    return <hr className="border-border" style={{ marginTop: "16px", marginBottom: "16px" }} />;
  },
  pre({ children }) {
    return (
      <pre className="bg-muted border border-border rounded-md overflow-hidden" style={{ marginTop: "12px", marginBottom: "12px" }}>
        {children}
      </pre>
    );
  },
  code({ className, children }) {
    const isBlock = className?.startsWith("language-");
    if (isBlock) {
      return (
        <code className={cn("block p-4 overflow-x-auto font-mono text-sm", className)}>
          {children}
        </code>
      );
    }
    return (
      <code className="bg-muted border border-border rounded-sm px-1.5 py-0.5 font-mono text-sm">
        {children}
      </code>
    );
  },
  a({ href, children }) {
    return (
      <a href={href} target="_blank" rel="noopener noreferrer" className="text-primary underline underline-offset-2 hover:opacity-80">
        {children}
      </a>
    );
  },
  blockquote({ children }) {
    return (
      <blockquote className="border-l-[3px] border-border py-1 px-3 text-muted-foreground" style={{ marginTop: "12px", marginBottom: "12px" }}>
        {children}
      </blockquote>
    );
  },
  table({ children }) {
    return (
      <div className="overflow-x-auto">
        <table className="w-full border-collapse text-sm">{children}</table>
      </div>
    );
  },
  th({ children }) {
    return (
      <th className="border border-border px-3 py-1.5 text-left font-semibold bg-muted">
        {children}
      </th>
    );
  },
  td({ children }) {
    return (
      <td className="border border-border px-3 py-1.5 text-left">
        {children}
      </td>
    );
  },
};

interface MarkdownProps {
  children: string;
}

export const Markdown = memo(function Markdown({ children }: MarkdownProps) {
  return (
    <div className="text-foreground text-sm" style={{ lineHeight: "1.625em" }}>
      <ReactMarkdown
        remarkPlugins={REMARK_PLUGINS}
        rehypePlugins={REHYPE_PLUGINS}
        components={components}
      >
        {children}
      </ReactMarkdown>
    </div>
  );
});

import { memo, useState, useCallback } from "react";
import type { Message, TurnMetadata } from "../types.js";
import { cn } from "../lib/utils.js";
import { Markdown } from "./Markdown.js";
import { StreamingIndicator } from "./StreamingIndicator.js";
import { PartRenderer } from "../parts/PartRenderer.js";
import { PartErrorBoundary } from "../parts/PartErrorBoundary.js";
import type { DisplayRendererMap } from "../display/registry.js";
import { Copy, Check, Clock, Coins, Cpu } from "lucide-react";
import { useTranslation } from "../i18n/index.js";

export interface MessageBubbleProps {
  message: Message;
  isStreaming?: boolean;
  displayRenderers?: DisplayRendererMap;
  className?: string;
}

function extractText(message: Message): string {
  if (message.content) return message.content;
  if (!Array.isArray(message.parts)) return "";
  return message.parts
    .filter((p): p is { type: "text"; text: string } => (p as { type: string }).type === "text")
    .map((p) => p.text)
    .join("\n");
}

function CopyButton({ text }: { text: string }) {
  const { t } = useTranslation();
  const [copied, setCopied] = useState(false);

  const handleCopy = useCallback(async () => {
    await navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  }, [text]);

  return (
    <button
      type="button"
      onClick={handleCopy}
      className={cn(
        "h-7 w-7 flex items-center justify-center rounded-lg transition-all",
        "text-muted-foreground/50 opacity-0 group-hover/bubble:opacity-100",
        "hover:bg-muted/50 hover:text-muted-foreground",
      )}
      aria-label={copied ? t("bubble.copied") : t("bubble.copy")}
    >
      {copied ? <Check className="h-3.5 w-3.5" /> : <Copy className="h-3.5 w-3.5" />}
    </button>
  );
}

function EmptyResponse() {
  const { t } = useTranslation();
  return <span className="text-xs italic text-muted-foreground">{t("bubble.emptyResponse")}</span>;
}

function TurnFooter({ meta }: { meta: TurnMetadata }) {
  const { t } = useTranslation();
  const items: Array<{ icon: typeof Clock; text: string }> = [];

  if (meta.durationMs != null) {
    const secs = (meta.durationMs / 1000).toFixed(1);
    items.push({ icon: Clock, text: `${secs}s` });
  }

  if (meta.costUsd != null) {
    const cost = meta.costUsd < 0.01
      ? `$${meta.costUsd.toFixed(4)}`
      : `$${meta.costUsd.toFixed(3)}`;
    items.push({ icon: Coins, text: cost });
  }

  if (meta.inputTokens != null || meta.outputTokens != null) {
    const parts: string[] = [];
    if (meta.inputTokens != null) parts.push(`${formatTokens(meta.inputTokens)} ${t("bubble.tokenIn")}`);
    if (meta.outputTokens != null) parts.push(`${formatTokens(meta.outputTokens)} ${t("bubble.tokenOut")}`);
    if (meta.cachedTokens != null && meta.cachedTokens > 0) parts.push(`${formatTokens(meta.cachedTokens)} ${t("bubble.tokenCached")}`);
    items.push({ icon: Cpu, text: parts.join(" / ") });
  }

  if (meta.model) {
    items.push({ icon: Cpu, text: meta.model });
  }

  if (items.length === 0) return null;

  return (
    <div className="flex flex-wrap items-center gap-3 mt-1 text-[10px] text-muted-foreground/60">
      {items.map(({ icon: Icon, text }, i) => (
        <span key={i} className="flex items-center gap-1">
          <Icon className="size-3" />
          {text}
        </span>
      ))}
    </div>
  );
}

function formatTokens(n: number): string {
  if (n >= 1_000_000) return `${(n / 1_000_000).toFixed(1)}M`;
  if (n >= 1_000) return `${(n / 1_000).toFixed(1)}k`;
  return String(n);
}

export const MessageBubble = memo(function MessageBubble({ message, isStreaming, displayRenderers, className }: MessageBubbleProps) {
  const isUser = message.role === "user";
  const hasParts = Array.isArray(message.parts) && message.parts.length > 0;
  const hasText = typeof message.content === "string" && message.content.length > 0;
  const isEmptyAssistant = !isUser && !hasParts && !hasText && !isStreaming;

  return (
    <div className={cn("group/bubble", isUser ? "flex flex-col items-end" : "flex flex-col items-start")}>
      {/* Bubble */}
      <div
        className={cn(
          "min-w-0 overflow-hidden",
          isUser
            ? "max-w-[80%] rounded-lg rounded-br-sm bg-muted text-foreground px-4 py-2.5"
            : "w-full text-foreground py-1",
          className
        )}
      >
        {hasParts
          ? <div className="flex flex-col gap-3">
              {(message.parts as { type: string }[]).map((part, i) => (
                <PartErrorBoundary key={i} label={`part:${part.type}`}>
                  <PartRenderer
                    part={part as Parameters<typeof PartRenderer>[0]["part"]}
                    isStreaming={isStreaming}
                    displayRenderers={displayRenderers}
                  />
                </PartErrorBoundary>
              ))}
            </div>
          : hasText
            ? <Markdown>{message.content}</Markdown>
            : isEmptyAssistant
              ? <EmptyResponse />
              : null
        }
        {isStreaming && !isUser && <StreamingIndicator />}
      </div>

      {/* Action bar + turn footer — outside bubble, below */}
      {!isStreaming && (
        <div className={cn(
          "flex items-center gap-0.5 mt-0.5",
          isUser ? "justify-end" : "justify-start"
        )}>
          <CopyButton text={extractText(message)} />
        </div>
      )}
      {!isUser && message.turnMeta && !isStreaming && (
        <TurnFooter meta={message.turnMeta} />
      )}
    </div>
  );
}, (prev, next) =>
  prev.message === next.message
  && prev.message.turnMeta === next.message.turnMeta
  && prev.isStreaming === next.isStreaming
  && prev.displayRenderers === next.displayRenderers
  && prev.className === next.className
);

import { useRef, useEffect, useState, useCallback } from "react";
import { Send, Square, Plus, Mic, X, Camera, Paperclip, Image as ImageIcon, CircleStop, Loader2 } from "lucide-react";
import { Button } from "../ui/button.js";
import { cn } from "../lib/utils.js";
import { useTranslation } from "../i18n/index.js";

// ── Types ──

export interface Attachment {
  id: string;
  file: File;
  preview?: string;
  type: "image" | "file" | "audio";
}

export interface MessageInputProps {
  input: string;
  setInput: (value: string) => void;
  handleSubmit: (e: React.FormEvent, attachments?: Attachment[]) => void;
  isLoading?: boolean;
  isUploading?: boolean;
  stop?: () => void;
  placeholder?: string;
  className?: string;
  enableAttachments?: boolean;
  enableVoice?: boolean;
  /** Slot para conteudo extra abaixo do input (ex: model select). */
  bottomSlot?: React.ReactNode;
}

// ── Constants ──

const LINE_HEIGHT_PX = 24;
const MAX_ROWS = 10;
const MULTILINE_THRESHOLD_PX = LINE_HEIGHT_PX * 1.5; // 36px — above this = multiline

// ── Recording Hook ──

function useAudioRecording(onComplete: (file: File) => void) {
  const [isRecording, setIsRecording] = useState(false);
  const [elapsed, setElapsed] = useState(0);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);
  const timerRef = useRef<ReturnType<typeof setInterval> | undefined>(undefined);

  const start = useCallback(async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const recorder = new MediaRecorder(stream);
      mediaRecorderRef.current = recorder;
      chunksRef.current = [];
      recorder.ondataavailable = (e) => { if (e.data.size > 0) chunksRef.current.push(e.data); };
      recorder.onstop = () => {
        const blob = new Blob(chunksRef.current, { type: "audio/webm" });
        const file = new File([blob], `audio-${Date.now()}.webm`, { type: "audio/webm" });
        stream.getTracks().forEach((t) => t.stop());
        onComplete(file);
      };
      recorder.start();
      setIsRecording(true);
      setElapsed(0);
      timerRef.current = setInterval(() => setElapsed((s) => s + 1), 1000);
    } catch { /* permission denied */ }
  }, [onComplete]);

  const stop = useCallback(() => {
    mediaRecorderRef.current?.stop();
    setIsRecording(false);
    clearInterval(timerRef.current);
  }, []);

  const cancel = useCallback(() => {
    if (mediaRecorderRef.current) {
      mediaRecorderRef.current.onstop = null;
      mediaRecorderRef.current.stop();
      mediaRecorderRef.current.stream.getTracks().forEach((t) => t.stop());
    }
    setIsRecording(false);
    setElapsed(0);
    clearInterval(timerRef.current);
  }, []);

  useEffect(() => () => clearInterval(timerRef.current), []);

  return { isRecording, elapsed, start, stop, cancel };
}

function formatTime(seconds: number): string {
  const m = Math.floor(seconds / 60);
  const s = seconds % 60;
  return `${m}:${s.toString().padStart(2, "0")}`;
}

// ── Attachment Preview ──

function AttachmentPreview({ attachment, onRemove }: { attachment: Attachment; onRemove: () => void }) {
  const { t } = useTranslation();
  return (
    <div className="relative group shrink-0">
      {attachment.type === "image" && attachment.preview ? (
        <div className="relative h-16 w-16 rounded-lg overflow-hidden border border-border/50">
          <img src={attachment.preview} alt={attachment.file.name} className="h-full w-full object-cover" />
        </div>
      ) : (
        <div className="flex items-center gap-2 rounded-lg border border-border/50 bg-background/50 px-3 py-2">
          <Paperclip className="h-4 w-4 text-muted-foreground shrink-0" />
          <span className="text-xs text-muted-foreground truncate max-w-[120px]">{attachment.file.name}</span>
        </div>
      )}
      <button
        type="button"
        onClick={onRemove}
        className="absolute -top-1.5 -right-1.5 h-5 w-5 rounded-full bg-foreground text-background flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity"
        aria-label={t("input.remove")}
      >
        <X className="h-3 w-3" />
      </button>
    </div>
  );
}

// ── Plus Menu ──

function PlusMenu({ onFile, onCamera, onGallery, onClose }: {
  onFile: () => void; onCamera: () => void; onGallery: () => void; onClose: () => void;
}) {
  const { t } = useTranslation();
  const menuRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    function handleClick(e: MouseEvent) {
      if (menuRef.current && !menuRef.current.contains(e.target as Node)) onClose();
    }
    document.addEventListener("mousedown", handleClick);
    return () => document.removeEventListener("mousedown", handleClick);
  }, [onClose]);

  return (
    <div
      ref={menuRef}
      style={{
        position: "absolute",
        bottom: "calc(100% + 8px)",
        left: 0,
        zIndex: 50,
      }}
      className="rounded-xl border border-border bg-popover text-popover-foreground shadow-lg py-1 min-w-[160px]"
    >
      {[
        { icon: Paperclip, label: t("input.file"), onClick: onFile },
        { icon: Camera, label: t("input.camera"), onClick: onCamera },
        { icon: ImageIcon, label: t("input.gallery"), onClick: onGallery },
      ].map((item) => (
        <button
          key={item.label}
          type="button"
          onClick={() => { item.onClick(); onClose(); }}
          className="flex w-full items-center gap-3 px-4 py-2.5 text-sm hover:bg-muted/50 transition-colors"
        >
          <item.icon className="h-4 w-4 text-muted-foreground" />
          {item.label}
        </button>
      ))}
    </div>
  );
}

// ── Main Component ──

export function MessageInput({
  input,
  setInput,
  handleSubmit,
  isLoading,
  isUploading = false,
  stop,
  placeholder,
  className,
  enableAttachments = true,
  enableVoice = true,
  bottomSlot,
}: MessageInputProps) {
  const { t } = useTranslation();
  const resolvedPlaceholder = placeholder ?? t("input.placeholder");
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const imageInputRef = useRef<HTMLInputElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const [attachments, setAttachments] = useState<Attachment[]>([]);
  const [showMenu, setShowMenu] = useState(false);
  const [isDragging, setIsDragging] = useState(false);
  const [isMultiline, setIsMultiline] = useState(false);
  const historyRef = useRef<string[]>([]);
  const historyPosRef = useRef(-1);
  const savedInputRef = useRef("");

  const onRecordingComplete = useCallback((file: File) => {
    const att: Attachment = { id: crypto.randomUUID(), file, type: "audio" };
    setAttachments((prev) => [...prev, att]);
  }, []);

  const { isRecording, elapsed, start: startRecording, stop: stopRecording, cancel: cancelRecording } = useAudioRecording(onRecordingComplete);

  const hasContent = input.trim().length > 0 || attachments.length > 0;

  // Auto-focus
  useEffect(() => { textareaRef.current?.focus(); }, []);

  // Auto-expand — stable measurement with height:auto
  useEffect(() => {
    const el = textareaRef.current;
    if (!el) return;
    el.style.height = "auto";
    const scrollH = el.scrollHeight;
    const maxH = MAX_ROWS * LINE_HEIGHT_PX;
    const clampedH = Math.min(scrollH, maxH);
    el.style.height = `${clampedH}px`;
    setIsMultiline(scrollH > MULTILINE_THRESHOLD_PX);
  }, [input]);

  // ── Attachments ──

  const addFiles = useCallback((files: FileList | File[]) => {
    const newAttachments: Attachment[] = Array.from(files).map((file) => {
      const isImage = file.type.startsWith("image/");
      const att: Attachment = { id: crypto.randomUUID(), file, type: isImage ? "image" : "file" };
      if (isImage) {
        const reader = new FileReader();
        reader.onload = (e) => {
          setAttachments((prev) => prev.map((a) => (a.id === att.id ? { ...a, preview: e.target?.result as string } : a)));
        };
        reader.readAsDataURL(file);
      }
      return att;
    });
    setAttachments((prev) => [...prev, ...newAttachments]);
  }, []);

  const removeAttachment = useCallback((id: string) => {
    setAttachments((prev) => prev.filter((a) => a.id !== id));
  }, []);

  // ── Drag & Drop ──

  const handleDragOver = useCallback((e: React.DragEvent) => { e.preventDefault(); setIsDragging(true); }, []);

  const handleDragLeave = useCallback((e: React.DragEvent) => {
    if (containerRef.current && !containerRef.current.contains(e.relatedTarget as Node)) setIsDragging(false);
  }, []);

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault(); setIsDragging(false);
    if (e.dataTransfer.files.length) addFiles(e.dataTransfer.files);
  }, [addFiles]);

  // ── Clipboard Paste ──

  const handlePaste = useCallback((e: React.ClipboardEvent) => {
    const files: File[] = [];
    for (let i = 0; i < e.clipboardData.items.length; i++) {
      if (e.clipboardData.items[i].kind === "file") {
        const file = e.clipboardData.items[i].getAsFile();
        if (file) files.push(file);
      }
    }
    if (files.length) { e.preventDefault(); addFiles(files); }
  }, [addFiles]);

  // ── Submit ──

  function onSubmit(e: React.FormEvent) {
    e.preventDefault();
    if (!hasContent || isLoading) return;
    if (input.trim()) {
      historyRef.current.unshift(input);
      if (historyRef.current.length > 50) historyRef.current.length = 50;
    }
    historyPosRef.current = -1;
    savedInputRef.current = "";
    handleSubmit(e, attachments.length > 0 ? attachments : undefined);
    setAttachments([]);
  }

  function handleKeyDown(e: React.KeyboardEvent<HTMLTextAreaElement>) {
    // History navigation — only when cursor is at start/end and not multiline content
    const el = textareaRef.current;
    if (e.key === "ArrowUp" && historyRef.current.length > 0 && el) {
      const atTop = el.selectionStart === 0 && el.selectionEnd === 0;
      const isEmpty = input === "";
      if (atTop || isEmpty) {
        e.preventDefault();
        if (historyPosRef.current === -1) savedInputRef.current = input;
        const nextPos = Math.min(historyPosRef.current + 1, historyRef.current.length - 1);
        if (nextPos !== historyPosRef.current) {
          historyPosRef.current = nextPos;
          setInput(historyRef.current[nextPos]);
        }
        return;
      }
    }

    if (e.key === "ArrowDown" && historyPosRef.current >= 0 && el) {
      const atBottom = el.selectionStart === input.length;
      if (atBottom) {
        e.preventDefault();
        const nextPos = historyPosRef.current - 1;
        historyPosRef.current = nextPos;
        setInput(nextPos < 0 ? savedInputRef.current : historyRef.current[nextPos]);
        return;
      }
    }

    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      if (hasContent && !isLoading) onSubmit(e as unknown as React.FormEvent);
    }
  }

  // ── Render ──

  return (
    <div
      ref={containerRef}
      onDragOver={enableAttachments ? handleDragOver : undefined}
      onDragLeave={enableAttachments ? handleDragLeave : undefined}
      onDrop={enableAttachments ? handleDrop : undefined}
      className={cn(
        "relative border border-border/50 bg-muted transition-[border-radius] duration-200",
        isMultiline || attachments.length > 0 || bottomSlot ? "rounded-2xl" : "rounded-full",
        isDragging && "ring-2 ring-primary/50",
        className,
      )}
    >
      {/* ── Drag overlay ── */}
      {isDragging && (
        <div className="absolute inset-0 z-10 flex items-center justify-center rounded-[inherit] bg-primary/5 border-2 border-dashed border-primary/30">
          <span className="text-sm text-primary font-medium">{t("input.dropHere")}</span>
        </div>
      )}

      {/* ── Recording overlay ── */}
      {isRecording && (
        <div className="flex items-center gap-3 px-3 py-2">
          <Button type="button" variant="ghost" size="icon" onClick={cancelRecording} className="h-8 w-8 rounded-full shrink-0 text-muted-foreground" aria-label={t("input.cancel")}>
            <X className="h-4 w-4" />
          </Button>
          <div className="flex items-center gap-2 flex-1">
            <span className="h-2 w-2 rounded-full bg-destructive animate-pulse" />
            <span className="text-sm font-medium tabular-nums">{formatTime(elapsed)}</span>
            <div className="flex-1 flex items-center gap-0.5 px-2">
              {Array.from({ length: 20 }, (_, i) => (
                <span key={i} className="w-1 bg-foreground/30 rounded-full" style={{ height: `${4 + Math.random() * 12}px` }} />
              ))}
            </div>
          </div>
          <Button type="button" size="icon" onClick={stopRecording} className="h-8 w-8 rounded-full shrink-0" aria-label={t("input.stop")}>
            <CircleStop className="h-4 w-4" />
          </Button>
        </div>
      )}

      {/* ── Main content (hidden when recording) ── */}
      <div className={cn(isRecording && "hidden")}>
        {/* Attachment previews */}
        {(attachments.length > 0 || isUploading) && (
          <div className="flex flex-wrap gap-2 px-4 pt-3 pb-1">
            {attachments.map((att) => (
              <AttachmentPreview key={att.id} attachment={att} onRemove={() => removeAttachment(att.id)} />
            ))}
            {isUploading && (
              <div className="flex items-center gap-2 rounded-lg border border-border/50 bg-background/50 px-3 py-2 text-xs text-muted-foreground">
                <Loader2 className="h-4 w-4 animate-spin shrink-0" />
                <span>{t("input.uploading")}</span>
              </div>
            )}
          </div>
        )}

        {/* ── Single unified input row ── */}
        <div className={cn("flex gap-1 p-1.5", isMultiline ? "items-end" : "items-center")}>
          {/* Left: Plus button */}
          {enableAttachments && (
            <div className="relative shrink-0">
              <Button type="button" variant="ghost" size="icon" className="h-8 w-8 rounded-full" onClick={() => setShowMenu(!showMenu)} aria-label={t("input.add")}>
                <Plus className="h-4 w-4" />
              </Button>
              {showMenu && (
                <PlusMenu
                  onFile={() => fileInputRef.current?.click()}
                  onCamera={() => imageInputRef.current?.click()}
                  onGallery={() => imageInputRef.current?.click()}
                  onClose={() => setShowMenu(false)}
                />
              )}
            </div>
          )}

          {/* Center: Textarea */}
          <textarea
            ref={textareaRef}
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={handleKeyDown}
            onPaste={enableAttachments ? handlePaste : undefined}
            placeholder={resolvedPlaceholder}
            rows={1}
            disabled={isLoading}
            aria-label={t("input.message")}
            className="flex-1 min-w-0 bg-transparent text-foreground text-sm resize-none outline-none placeholder:text-muted-foreground leading-6 py-1 px-2"
          />

          {/* Right: Action buttons */}
          <div className="flex items-center gap-0.5 shrink-0">
            {enableVoice && !hasContent && (
              <Button type="button" variant="ghost" size="icon" className="h-8 w-8 rounded-full text-muted-foreground" onClick={startRecording} aria-label={t("input.record")}>
                <Mic className="h-4 w-4" />
              </Button>
            )}
            {isLoading && stop ? (
              <Button type="button" variant="ghost" size="icon" onClick={stop} className="h-8 w-8 rounded-full" aria-label={t("input.stopGeneration")}>
                <Square className="h-4 w-4" />
              </Button>
            ) : (
              <Button type="button" size="icon" onClick={onSubmit} disabled={!hasContent || !!isLoading} className="h-8 w-8 rounded-full" aria-label={t("input.send")}>
                <Send className="h-4 w-4" />
              </Button>
            )}
          </div>
        </div>

        {/* ── Bottom slot (model select, etc.) ── */}
        {bottomSlot && (
          <div className="flex items-center justify-end border-t border-border/30 px-3 py-1.5">
            {bottomSlot}
          </div>
        )}
      </div>

      {/* Hidden file inputs */}
      <input ref={fileInputRef} type="file" multiple className="hidden" onChange={(e) => { if (e.target.files) addFiles(e.target.files); e.target.value = ""; }} />
      <input ref={imageInputRef} type="file" accept="image/*" multiple className="hidden" onChange={(e) => { if (e.target.files) addFiles(e.target.files); e.target.value = ""; }} />
    </div>
  );
}

import * as ScrollAreaPrimitive from "@radix-ui/react-scroll-area";
import { useRef, useEffect, useMemo, useCallback, useState, type ReactNode } from "react";
import { useVirtualizer } from "@tanstack/react-virtual";
import { Sparkles, Loader2 } from "lucide-react";
import type { Message } from "../types.js";
import { MessageBubble } from "./MessageBubble.js";
import { StreamingIndicator } from "./StreamingIndicator.js";
import { ErrorNote } from "./ErrorNote.js";
import type { DisplayRendererMap } from "../display/registry.js";
import { ScrollBar } from "../ui/scroll-area.js";
import { cn } from "../lib/utils.js";
import { useTranslation } from "../i18n/index.js";

export interface MessageListProps {
  messages: Message[];
  isLoading?: boolean;
  displayRenderers?: DisplayRendererMap;
  className?: string;
  error?: Error;
  onRetry?: () => void;
  emptyState?: ReactNode;
  /** Whether there are older messages to load. */
  hasMore?: boolean;
  /** Called when the user scrolls near the top and hasMore is true. */
  onLoadMore?: () => void;
  /** Whether older messages are currently being loaded. */
  isLoadingMore?: boolean;
}

function LoadingOlder() {
  const { t } = useTranslation();
  return (
    <div className="flex items-center justify-center gap-2 py-3 text-xs text-muted-foreground">
      <Loader2 className="size-3.5 animate-spin" />
      <span>{t("chat.loadingOlder")}</span>
    </div>
  );
}

function ConversationStart() {
  const { t } = useTranslation();
  return (
    <div className="flex items-center justify-center py-3 text-xs text-muted-foreground">
      <span>{t("chat.conversationStart")}</span>
    </div>
  );
}

function DefaultWelcome() {
  const { t } = useTranslation();
  return (
    <div className="flex h-full flex-col items-center justify-center gap-4 px-6 py-16 text-center">
      <div className="flex size-14 items-center justify-center rounded-2xl bg-primary/10 text-primary ring-1 ring-primary/20">
        <Sparkles className="size-7" />
      </div>
      <div className="space-y-1.5">
        <h2 className="text-xl font-semibold tracking-tight">{t("chat.welcomeTitle")}</h2>
        <p className="max-w-sm text-sm text-muted-foreground">
          {t("chat.welcomeDescription")}
        </p>
      </div>
    </div>
  );
}

export function MessageList({ messages, isLoading, displayRenderers, className, error, onRetry, emptyState, hasMore, onLoadMore, isLoadingMore }: MessageListProps) {
  const viewportRef = useRef<HTMLDivElement>(null);
  const isFollowingRef = useRef(true);
  const loadMoreDebounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const lastAssistantIndex = useMemo(() =>
    messages.reduceRight((found, msg, i) => {
      if (found !== -1) return found;
      return msg.role === "assistant" ? i : -1;
    }, -1),
    [messages]
  );

  const virtualizer = useVirtualizer({
    count: messages.length,
    getScrollElement: () => viewportRef.current,
    estimateSize: () => 80,
    overscan: 5,
    paddingStart: 16,
  });

  // Track scroll position to detect if user is following + trigger load more
  const handleScroll = useCallback(() => {
    const viewport = viewportRef.current;
    if (!viewport) return;
    const distanceFromBottom =
      viewport.scrollHeight - viewport.scrollTop - viewport.clientHeight;
    isFollowingRef.current = distanceFromBottom <= 100;

    // Infinite scroll reverse: load more when near top
    if (hasMore && !isLoadingMore && onLoadMore && viewport.scrollTop < 200) {
      if (loadMoreDebounceRef.current) clearTimeout(loadMoreDebounceRef.current);
      loadMoreDebounceRef.current = setTimeout(() => {
        onLoadMore();
        loadMoreDebounceRef.current = null;
      }, 300);
    }
  }, [hasMore, isLoadingMore, onLoadMore]);

  useEffect(() => {
    const viewport = viewportRef.current;
    if (!viewport) return;
    viewport.addEventListener("scroll", handleScroll, { passive: true });
    return () => viewport.removeEventListener("scroll", handleScroll);
  }, [handleScroll]);

  // Auto-scroll to bottom when following
  useEffect(() => {
    if (messages.length > 0 && isFollowingRef.current) {
      virtualizer.scrollToIndex(messages.length - 1, { align: "end" });
    }
  }, [messages, virtualizer]);

  // Auto-scroll when error appears
  useEffect(() => {
    if (error && isFollowingRef.current) {
      const viewport = viewportRef.current;
      if (viewport) viewport.scrollTop = viewport.scrollHeight;
    }
  }, [error]);

  const virtualItems = virtualizer.getVirtualItems();

  if (messages.length === 0) {
    return (
      <ScrollAreaPrimitive.Root className={cn("flex-1 relative overflow-hidden", className)}>
        <ScrollAreaPrimitive.Viewport ref={viewportRef} className="h-full w-full rounded-[inherit]">
          {emptyState ?? <DefaultWelcome />}
        </ScrollAreaPrimitive.Viewport>
        <ScrollBar />
        <ScrollAreaPrimitive.Corner />
      </ScrollAreaPrimitive.Root>
    );
  }

  return (
    <ScrollAreaPrimitive.Root className={cn("flex-1 relative overflow-hidden", className)}>
      <ScrollAreaPrimitive.Viewport ref={viewportRef} className="h-full w-full rounded-[inherit]">
        {/* Load more indicator / conversation start */}
        {isLoadingMore && (
          <LoadingOlder />
        )}
        {!isLoadingMore && hasMore === false && messages.length > 0 && (
          <ConversationStart />
        )}

        <div
          className="relative w-full"
          style={{ height: virtualizer.getTotalSize() + 16 }}
        >
          <div>
            {virtualItems.map((virtualRow) => {
              const message = messages[virtualRow.index];
              return (
                <div
                  key={message.id ?? virtualRow.index}
                  data-index={virtualRow.index}
                  ref={virtualizer.measureElement}
                  className="pb-3 px-4"
                  style={{
                    position: "absolute",
                    top: 0,
                    left: 0,
                    right: 0,
                    transform: `translateY(${virtualRow.start}px)`,
                  }}
                >
                  <MessageBubble
                    message={message}
                    isStreaming={virtualRow.index === lastAssistantIndex && isLoading && messages[messages.length - 1]?.role === "assistant"}
                    displayRenderers={displayRenderers}
                  />
                </div>
              );
            })}
          </div>
        </div>
        {isLoading && messages[messages.length - 1]?.role !== "assistant" && (
          <div className="px-4 pb-3">
            <StreamingIndicator />
          </div>
        )}
        {!isLoading && error && (
          <div className="px-4 pb-3">
            <ErrorNote message={error.message} onRetry={onRetry} />
          </div>
        )}
      </ScrollAreaPrimitive.Viewport>
      <ScrollBar />
      <ScrollAreaPrimitive.Corner />
    </ScrollAreaPrimitive.Root>
  );
}

