export interface UseHistoryDataReturn {
  conversations: Conversation[]
  groups: ConversationGroup[]
  searchQuery: string
  setSearchQuery: (q: string) => void
  filteredGroups: ConversationGroup[]
  isLoading: boolean
  refresh: () => Promise<void>
  createConversation: () => Promise<string>
  renameConversation: (id: string, title: string) => Promise<void>
  deleteConversation: (id: string) => Promise<void>
  toggleStar: (id: string) => Promise<void>
}

export function useHistoryData(
  transport: ChatTransport,
  options?: {
    agentId?: string;
    registerRefresh?: (fn: () => Promise<void>) => void;
    /** When defined, search query is controlled externally (e.g. by a host shell). */
    externalSearchQuery?: string;
    /** Callback invoked when search changes while controlled externally. */
    onExternalSearchChange?: (q: string) => void;
  },
): UseHistoryDataReturn {
  const { t } = useTranslation()
  const transportRef = useRef(transport)
  transportRef.current = transport
  const agentIdRef = useRef(options?.agentId)
  agentIdRef.current = options?.agentId

  const [conversations, setConversations] = useState<Conversation[]>([])
  const [internalSearchQuery, setInternalSearchQuery] = useState("")
  const [isLoading, setIsLoading] = useState(true)

  const isControlled = options?.externalSearchQuery !== undefined
  const searchQuery = isControlled ? (options!.externalSearchQuery as string) : internalSearchQuery
  const setSearchQuery = useCallback(
    (q: string) => {
      if (isControlled) options?.onExternalSearchChange?.(q)
      else setInternalSearchQuery(q)
    },
    [isControlled, options],
  )

  const refresh = useCallback(async () => {
    setIsLoading(true)
    try {
      const items = await transportRef.current.listConversations(
        agentIdRef.current ? { agentId: agentIdRef.current } : undefined,
      )
      setConversations(items)
    } finally {
      setIsLoading(false)
    }
  }, [])

  // Register refresh in provider context so external consumers can trigger it (D-10)
  useEffect(() => {
    options?.registerRefresh?.(refresh)
  }, [refresh, options?.registerRefresh])

  useEffect(() => {
    void refresh()
  }, [refresh])

  // Auto-refresh when localStorage history changes (e.g. from ChatHeader actions)
  useEffect(() => {
    const handler = () => void refresh()
    window.addEventListener(HISTORY_CHANGE_EVENT, handler)
    return () => window.removeEventListener(HISTORY_CHANGE_EVENT, handler)
  }, [refresh])

  const groups = groupConversations(conversations, t)

  // Filtered (flat, no temporal grouping during search)
  const filteredGroups: ConversationGroup[] = searchQuery.trim()
    ? (() => {
        const q = searchQuery.toLowerCase()
        const matches = conversations
          .filter((c) => c.title.toLowerCase().includes(q))
          .sort((a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime())
        return matches.length ? [{ label: t("history.results"), conversations: matches }] : []
      })()
    : groups

  const createConversation = useCallback(async () => {
    const { sessionId } = await transportRef.current.createConversation(
      agentIdRef.current ? { agentId: agentIdRef.current } : undefined,
    )
    // Rename to locale-aware default title
    await transportRef.current.updateConversation(sessionId, { title: t("history.newConversation") })
    await refresh()
    return sessionId
  }, [refresh, t])

  const renameConversation = useCallback(
    async (id: string, title: string) => {
      await transportRef.current.updateConversation(id, { title })
      await refresh()
    },
    [refresh],
  )

  const deleteConversation = useCallback(
    async (id: string) => {
      await transportRef.current.deleteConversation(id)
      await refresh()
    },
    [refresh],
  )

  const toggleStar = useCallback(
    async (id: string) => {
      const c = conversations.find((x) => x.id === id)
      if (!c) return
      await transportRef.current.updateConversation(id, { starred: !c.starred })
      await refresh()
    },
    [conversations, refresh],
  )

  return {
    conversations,
    groups,
    searchQuery,
    setSearchQuery,
    filteredGroups,
    isLoading,
    refresh,
    createConversation,
    renameConversation,
    deleteConversation,
    toggleStar,
  }
}

import type { DisplayAlert } from "./sdk-types.js";
import { AlertCircle, AlertTriangle, CheckCircle, Info } from "lucide-react";
import { Alert, AlertDescription, AlertTitle } from "../ui/alert.js";

type AlertVariant = "info" | "warning" | "error" | "success";

const VARIANT_ICON: Record<AlertVariant, typeof Info> = {
  info: Info,
  warning: AlertTriangle,
  error: AlertCircle,
  success: CheckCircle,
};

export function AlertRenderer({ variant = "info", title, message }: DisplayAlert) {
  const Icon = VARIANT_ICON[variant as AlertVariant] ?? Info;
  return (
    <Alert variant={variant === "error" ? "destructive" : "default"}>
      <Icon />
      {title && <AlertTitle>{title}</AlertTitle>}
      <AlertDescription>{message}</AlertDescription>
    </Alert>
  );
}

import type { DisplayCarousel } from "./sdk-types.js";
import useEmblaCarousel from "embla-carousel-react";
import { ChevronLeft, ChevronRight } from "lucide-react";
import { useCallback, useEffect, useState } from "react";
import { Badge } from "../ui/badge";
import { Button } from "../ui/button";
import { Card, CardContent } from "../ui/card";
import { cn } from "../lib/utils";
import { useTranslation } from "../i18n/index.js";

export function CarouselRenderer({ title, items }: DisplayCarousel) {
  const { t, locale } = useTranslation();
  const [emblaRef, emblaApi] = useEmblaCarousel({ loop: false, dragFree: false });
  const [selectedIndex, setSelectedIndex] = useState(0);
  const [canScrollPrev, setCanScrollPrev] = useState(false);
  const [canScrollNext, setCanScrollNext] = useState(false);

  const onSelect = useCallback(() => {
    if (!emblaApi) return;
    setSelectedIndex(emblaApi.selectedScrollSnap());
    setCanScrollPrev(emblaApi.canScrollPrev());
    setCanScrollNext(emblaApi.canScrollNext());
  }, [emblaApi]);

  useEffect(() => {
    if (!emblaApi) return;
    onSelect();
    emblaApi.on("select", onSelect);
    emblaApi.on("reInit", onSelect);
    return () => {
      emblaApi.off("select", onSelect);
      emblaApi.off("reInit", onSelect);
    };
  }, [emblaApi, onSelect]);

  const scrollPrev = useCallback(() => emblaApi?.scrollPrev(), [emblaApi]);
  const scrollNext = useCallback(() => emblaApi?.scrollNext(), [emblaApi]);

  return (
    <div className="flex flex-col gap-3">
      {title && <p className="text-sm font-medium text-foreground">{title}</p>}

      <div className="flex items-center gap-2">
        <Button
          variant="outline"
          size="icon"
          className="rounded-full shrink-0"
          onClick={scrollPrev}
          disabled={!canScrollPrev}
          aria-label={t("carousel.previous")}
          type="button"
        >
          <ChevronLeft className="h-4 w-4" />
        </Button>

        <div className="overflow-hidden flex-1" ref={emblaRef}>
          <div className="flex">
            {items.map((item, index) => (
              <div key={index} className="flex-[0_0_80%] min-w-0 pl-3 first:pl-0">
                {item.url ? (
                  <a href={item.url} target="_blank" rel="noopener noreferrer" className="block">
                    <CarouselCard item={item} />
                  </a>
                ) : (
                  <CarouselCard item={item} />
                )}
              </div>
            ))}
          </div>
        </div>

        <Button
          variant="outline"
          size="icon"
          className="rounded-full shrink-0"
          onClick={scrollNext}
          disabled={!canScrollNext}
          aria-label={t("carousel.next")}
          type="button"
        >
          <ChevronRight className="h-4 w-4" />
        </Button>
      </div>

      {items.length > 1 && (
        <div className="flex items-center justify-center gap-1.5" role="tablist" aria-label={t("carousel.slides")}>
          {items.map((_, index) => (
            <button
              key={index}
              className={cn(
                "w-2 h-2 rounded-full transition-colors",
                index === selectedIndex ? "bg-primary" : "bg-muted"
              )}
              onClick={() => emblaApi?.scrollTo(index)}
              role="tab"
              aria-selected={index === selectedIndex}
              aria-label={`Slide ${index + 1}`}
              type="button"
            />
          ))}
        </div>
      )}
    </div>
  );
}

type CarouselItem = DisplayCarousel["items"][number];

function CarouselCard({ item }: { item: CarouselItem }) {
  const { locale } = useTranslation();
  return (
    <Card className="overflow-hidden">
      {item.image && (
        <div className="aspect-video overflow-hidden">
          <img src={item.image} alt={item.title} loading="lazy" className="w-full h-full object-cover" />
        </div>
      )}
      <CardContent className="p-3 space-y-1">
        <p className="font-medium text-sm text-foreground">{item.title}</p>
        {item.subtitle && (
          <p className="text-xs text-muted-foreground">{item.subtitle}</p>
        )}
        {item.price && (
          <p className="text-sm font-bold text-foreground">
            {new Intl.NumberFormat(locale, { style: "currency", currency: item.price.currency }).format(item.price.value)}
          </p>
        )}
        {item.badges && item.badges.length > 0 && (
          <div className="flex flex-wrap gap-1 pt-1">
            {item.badges.map((badge, i) => (
              <Badge key={i} variant={(badge.variant as string) === "destructive" ? "destructive" : (badge.variant as string) === "secondary" ? "secondary" : "default"}>
                {badge.label}
              </Badge>
            ))}
          </div>
        )}
      </CardContent>
    </Card>
  );
}

import type { DisplayChart } from "./sdk-types.js";
import {
  AreaChart,
  Area,
  BarChart,
  Bar,
  LineChart,
  Line,
  PieChart,
  Pie,
  Cell,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  XAxis,
  YAxis,
} from "recharts";
import { Card } from "../ui/card";

const CHART_COLORS = [
  "var(--chart-1)",
  "var(--chart-2)",
  "var(--chart-3)",
  "var(--chart-4)",
  "var(--chart-5)",
];

const AXIS_PROPS = {
  stroke: "var(--border)",
  tick: { fill: "var(--muted-foreground)", fontSize: 12 },
};

const TOOLTIP_STYLE = {
  contentStyle: {
    background: "var(--card)",
    border: "1px solid var(--border)",
    color: "var(--card-foreground)",
    borderRadius: "0.375rem",
    fontSize: "0.75rem",
  },
};

function formatValue(value: number, format?: DisplayChart["format"]): string {
  if (!format) return String(value);
  const locale = format.locale ?? "en-US";
  const prefix = format.prefix ?? "";
  const suffix = format.suffix ?? "";
  if (prefix.includes("R$") || prefix.includes("$") || prefix.includes("€")) {
    const currencyMap: Record<string, string> = {
      "R$": "BRL",
      "$": "USD",
      "€": "EUR",
    };
    const currency = Object.keys(currencyMap).find(k => prefix.includes(k));
    if (currency) {
      return new Intl.NumberFormat(locale, { style: "currency", currency: currencyMap[currency] }).format(value);
    }
  }
  if (suffix.includes("%")) {
    return new Intl.NumberFormat(locale, { style: "percent", maximumFractionDigits: 1 }).format(value / 100);
  }
  const formatted = new Intl.NumberFormat(locale).format(value);
  return `${prefix}${formatted}${suffix}`;
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any
function makeTooltipFormatter(format?: DisplayChart["format"]): any {
  return (value: number | string | undefined): [string, string] => [
    typeof value === "number" ? formatValue(value, format) : String(value ?? ""),
    "",
  ];
}

export function ChartRenderer({ type, title, data, format }: DisplayChart) {
  const chartData = data.map((d) => ({ name: d.label, value: d.value, color: d.color }));
  const tooltipFormatter = makeTooltipFormatter(format);

  const sharedProps = {
    data: chartData,
    margin: { top: 4, right: 8, left: 8, bottom: 4 },
  };

  return (
    <Card className="p-4">
      {title && <p className="text-sm font-medium text-foreground mb-4">{title}</p>}
      <div className="min-h-[200px]">
        <ResponsiveContainer width="100%" height={200}>
          {renderChart(type, chartData, sharedProps, tooltipFormatter)}
        </ResponsiveContainer>
      </div>
    </Card>
  );
}

function renderChart(
  type: DisplayChart["type"],
  data: Array<{ name: string; value: number; color?: string }>,
  sharedProps: { data: typeof data; margin: { top: number; right: number; left: number; bottom: number } },
  tooltipFormatter: (v: number | string | undefined) => [string, string]
) {
  switch (type) {
    case "bar":
      return (
        <BarChart {...sharedProps}>
          <CartesianGrid strokeDasharray="3 3" stroke="var(--border)" />
          <XAxis dataKey="name" {...AXIS_PROPS} />
          <YAxis width={48} {...AXIS_PROPS} />
          <Tooltip formatter={tooltipFormatter} {...TOOLTIP_STYLE} />
          <Bar dataKey="value" radius={[4, 4, 0, 0]}>
            {data.map((entry, index) => (
              <Cell key={index} fill={entry.color ?? CHART_COLORS[index % CHART_COLORS.length]} />
            ))}
          </Bar>
        </BarChart>
      );

    case "line":
      return (
        <LineChart {...sharedProps}>
          <CartesianGrid strokeDasharray="3 3" stroke="var(--border)" />
          <XAxis dataKey="name" {...AXIS_PROPS} />
          <YAxis width={48} {...AXIS_PROPS} />
          <Tooltip formatter={tooltipFormatter} {...TOOLTIP_STYLE} />
          <Line
            type="monotone"
            dataKey="value"
            stroke={CHART_COLORS[0]}
            strokeWidth={2}
            dot={{ r: 4, fill: CHART_COLORS[0] }}
          />
        </LineChart>
      );

    case "area":
      return (
        <AreaChart {...sharedProps}>
          <CartesianGrid strokeDasharray="3 3" stroke="var(--border)" />
          <XAxis dataKey="name" {...AXIS_PROPS} />
          <YAxis width={48} {...AXIS_PROPS} />
          <Tooltip formatter={tooltipFormatter} {...TOOLTIP_STYLE} />
          <Area
            type="monotone"
            dataKey="value"
            stroke={CHART_COLORS[0]}
            fill={CHART_COLORS[0]}
            fillOpacity={0.2}
            strokeWidth={2}
          />
        </AreaChart>
      );

    case "pie":
      return (
        <PieChart>
          <Tooltip formatter={tooltipFormatter} {...TOOLTIP_STYLE} />
          <Pie
            data={data}
            dataKey="value"
            nameKey="name"
            cx="50%"
            cy="50%"
            outerRadius="70%"
            label={({ name }) => name}
            labelLine={{ stroke: "var(--muted-foreground)" }}
          >
            {data.map((entry, index) => (
              <Cell key={index} fill={entry.color ?? CHART_COLORS[index % CHART_COLORS.length]} />
            ))}
          </Pie>
        </PieChart>
      );

    case "donut":
      return (
        <PieChart>
          <Tooltip formatter={tooltipFormatter} {...TOOLTIP_STYLE} />
          <Pie
            data={data}
            dataKey="value"
            nameKey="name"
            cx="50%"
            cy="50%"
            innerRadius="40%"
            outerRadius="70%"
            label={({ name }) => name}
            labelLine={{ stroke: "var(--muted-foreground)" }}
          >
            {data.map((entry, index) => (
              <Cell key={index} fill={entry.color ?? CHART_COLORS[index % CHART_COLORS.length]} />
            ))}
          </Pie>
        </PieChart>
      );
  }
}

import type { DisplayChoices } from "./sdk-types.js";
import { useState } from "react";
import { Button } from "../ui/button.js";
import { Card } from "../ui/card.js";
import { cn } from "../lib/utils.js";
import { useTranslation } from "../i18n/index.js";

type ChoiceButtonsProps = DisplayChoices & {
  onChoiceSelect?: (value: string) => void;
};

export function ChoiceButtonsRenderer({
  question,
  choices,
  layout,
  onChoiceSelect,
}: ChoiceButtonsProps) {
  const { t } = useTranslation();
  const [selected, setSelected] = useState<string | null>(null);

  function handleSelect(id: string) {
    setSelected(id);
    onChoiceSelect?.(id);
  }

  return (
    <div className="space-y-3 w-fit">
      {question && <p className="text-sm font-medium text-foreground">{question}</p>}

      <div
        className={cn(
          layout === "buttons" && "flex flex-wrap gap-2",
          layout === "cards" && "grid grid-cols-1 sm:grid-cols-2 gap-2",
          layout === "list" && "flex flex-col gap-1"
        )}
        role="group"
        aria-label={question ?? t("choice.default")}
      >
        {choices.map((choice) => {
          const isSelected = selected === choice.id;

          if (layout === "buttons") {
            return (
              <Button
                key={choice.id}
                variant="outline"
                size="sm"
                onClick={() => handleSelect(choice.id)}
                aria-pressed={isSelected}
                className={cn(isSelected && "ring-2 ring-ring")}
              >
                {choice.icon && (
                  <span aria-hidden="true">{choice.icon}</span>
                )}
                {choice.label}
              </Button>
            );
          }

          if (layout === "cards") {
            return (
              <Card
                key={choice.id}
                className={cn(
                  "p-3 cursor-pointer hover:bg-muted/50 transition-colors",
                  isSelected && "ring-2 ring-ring"
                )}
                onClick={() => handleSelect(choice.id)}
                role="button"
                aria-pressed={isSelected}
              >
                {choice.icon && (
                  <span className="text-base" aria-hidden="true">{choice.icon}</span>
                )}
                <span className="block font-medium text-sm text-foreground">{choice.label}</span>
                {choice.description && (
                  <span className="block text-xs text-muted-foreground mt-1">{choice.description}</span>
                )}
              </Card>
            );
          }

          // list
          return (
            <button
              key={choice.id}
              className={cn(
                "flex items-center gap-3 w-full rounded-md px-3 py-2 text-sm text-left hover:bg-muted transition-colors",
                isSelected && "bg-muted ring-1 ring-ring"
              )}
              onClick={() => handleSelect(choice.id)}
              aria-pressed={isSelected}
            >
              <span
                className={cn(
                  "w-4 h-4 rounded-full border-2 border-input flex-shrink-0",
                  isSelected && "border-primary bg-primary"
                )}
                aria-hidden="true"
              />
              <span className="flex items-center gap-2 flex-1 min-w-0">
                {choice.icon && (
                  <span aria-hidden="true">{choice.icon}</span>
                )}
                <span className="font-medium text-foreground">{choice.label}</span>
                {choice.description && (
                  <span className="text-xs text-muted-foreground ml-auto">{choice.description}</span>
                )}
              </span>
            </button>
          );
        })}
      </div>
    </div>
  );
}

import type { DisplayCode } from "./sdk-types.js";
import { Check, Copy } from "lucide-react";
import { useState } from "react";
import { Button } from "../ui/button.js";
import { cn } from "../lib/utils.js";
import { useTranslation } from "../i18n/index.js";

export function CodeBlockRenderer({ language, code: rawCode, title, lineNumbers }: DisplayCode) {
  const { t } = useTranslation();
  const [copied, setCopied] = useState(false);

  // Guard: the PartRenderer normalizer may JSON-parse a code string that
  // happens to start with '{' or '['. Coerce back to string if needed.
  const code = typeof rawCode === "string" ? rawCode : JSON.stringify(rawCode, null, 2);

  async function handleCopy() {
    await navigator.clipboard.writeText(code);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  }

  const displayLines = lineNumbers
    ? code.split("\n").map((line, i) => (
        <span key={i} className="flex gap-4">
          <span className="select-none text-muted-foreground w-6 text-right shrink-0">{i + 1}</span>
          <span>{line}</span>
        </span>
      ))
    : code;

  return (
    <div className={cn("rounded-md border border-border bg-muted/30 overflow-hidden")}>
      <div className="flex items-center justify-between px-3 py-1.5 border-b border-border">
        <span className="text-xs text-muted-foreground font-mono">{title ?? language}</span>
        <Button
          variant="ghost"
          size="sm"
          onClick={handleCopy}
          aria-label={copied ? t("code.copied") : t("code.copy")}
          className="h-7 gap-1.5"
        >
          {copied ? <Check className="h-3 w-3" /> : <Copy className="h-3 w-3" />}
          <span className="text-xs">{copied ? t("code.copied") : t("code.copyLabel")}</span>
        </Button>
      </div>
      <pre className="p-4 overflow-x-auto font-mono text-sm">
        {lineNumbers ? (
          <code>{displayLines}</code>
        ) : (
          <code>{code}</code>
        )}
      </pre>
    </div>
  );
}

import { useState } from "react";
import type { DisplayComparison } from "./sdk-types.js";
import { CheckCircle } from "lucide-react";
import { ScrollArea, ScrollBar } from "../ui/scroll-area.js";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "../ui/table.js";
import { cn } from "../lib/utils.js";
import { useTranslation } from "../i18n/index.js";

export function ComparisonTableRenderer({ title, items, attributes }: DisplayComparison) {
  const { t, locale } = useTranslation();
  const formatMoney = (value: number, currency = "BRL") =>
    new Intl.NumberFormat(locale, { style: "currency", currency }).format(value);
  const [bestIdx, setBestIdx] = useState<number | null>(null);

  // Auto-detect best value by lowest price if no manual selection
  const lowestPriceIdx = items.reduce<number | null>((acc, item, i) => {
    if (!item.price) return acc;
    if (acc === null) return i;
    const best = items[acc]?.price;
    return best && item.price.value < best.value ? i : acc;
  }, null);

  const highlightIdx = bestIdx ?? lowestPriceIdx;

  return (
    <div className="space-y-2">
      {title && <h3 className="text-sm font-semibold text-foreground">{title}</h3>}

      <ScrollArea className="w-full">
        <Table>
          <TableHeader>
            <TableRow>
              <TableHead className="font-semibold text-center">{t("comparison.attribute")}</TableHead>
              {items.map((item, i) => (
                <TableHead
                  key={i}
                  className={cn(
                    "font-semibold text-center",
                    i === highlightIdx && "bg-muted"
                  )}
                >
                  <button
                    className="flex flex-col items-center gap-0.5 w-full cursor-pointer hover:opacity-80"
                    onClick={() => setBestIdx(i === bestIdx ? null : i)}
                    title={t("comparison.markBest")}
                  >
                    {i === highlightIdx && (
                      <CheckCircle className="h-3.5 w-3.5 text-primary" />
                    )}
                    <span className="font-semibold">{item.title}</span>
                    {item.price && (
                      <span className="text-xs text-muted-foreground font-normal">
                        {formatMoney(item.price.value, item.price.currency)}
                      </span>
                    )}
                  </button>
                </TableHead>
              ))}
            </TableRow>
          </TableHeader>

          <TableBody>
            {attributes && attributes.length > 0 ? (
              attributes.map((attr, ri) => (
                <TableRow key={ri}>
                  <TableCell className="font-medium">{attr.label}</TableCell>
                  {items.map((item, ci) => {
                    const val = (item as Record<string, unknown>)[attr.key];
                    return (
                      <TableCell
                        key={ci}
                        className={cn(
                          "text-center",
                          ci === highlightIdx && "bg-muted/50"
                        )}
                      >
                        {val === true ? "✓" : val === false ? "✗" : val != null ? String(val) : "—"}
                      </TableCell>
                    );
                  })}
                </TableRow>
              ))
            ) : (
              <>
                {items.some((i) => i.rating) && (
                  <TableRow>
                    <TableCell className="font-medium">{t("comparison.rating")}</TableCell>
                    {items.map((item, ci) => (
                      <TableCell
                        key={ci}
                        className={cn(
                          "text-center",
                          ci === highlightIdx && "bg-muted/50"
                        )}
                      >
                        {item.rating ? `${item.rating.score}/5 (${item.rating.count})` : "—"}
                      </TableCell>
                    ))}
                  </TableRow>
                )}
                {items.some((i) => i.description) && (
                  <TableRow>
                    <TableCell className="font-medium">{t("comparison.description")}</TableCell>
                    {items.map((item, ci) => (
                      <TableCell
                        key={ci}
                        className={cn(
                          "text-center",
                          ci === highlightIdx && "bg-muted/50"
                        )}
                      >
                        {item.description ?? "—"}
                      </TableCell>
                    ))}
                  </TableRow>
                )}
              </>
            )}
          </TableBody>
        </Table>
        <ScrollBar orientation="horizontal" />
      </ScrollArea>
    </div>
  );
}

import { useState } from "react";
import type { DisplayTable } from "./sdk-types.js";
import { ArrowUpDown, ArrowUp, ArrowDown } from "lucide-react";
import { Table, TableHeader, TableBody, TableRow, TableHead, TableCell } from "../ui/table.js";
import { ScrollArea, ScrollBar } from "../ui/scroll-area.js";
import { Button } from "../ui/button.js";
import { Badge } from "../ui/badge.js";
import { useTranslation } from "../i18n/index.js";

type SortDir = "asc" | "desc";

function formatMoney(value: number, locale: string, currency = "BRL") {
  return new Intl.NumberFormat(locale, { style: "currency", currency }).format(value);
}

function renderCellValue(value: unknown, type: string, locale: string): React.ReactNode {
  if (value == null) return "—";
  switch (type) {
    case "money":
      return typeof value === "number"
        ? formatMoney(value, locale)
        : typeof value === "object" && value !== null && "value" in value
        ? formatMoney((value as { value: number; currency?: string }).value, locale, (value as { currency?: string }).currency)
        : String(value);
    case "image":
      return typeof value === "string" ? (
        <img src={value} alt="" className="rounded-sm max-h-12 object-cover" loading="lazy" decoding="async" />
      ) : null;
    case "link":
      return typeof value === "string" ? (
        <a href={value} target="_blank" rel="noopener noreferrer" className="text-primary underline underline-offset-2 hover:opacity-80">
          {value}
        </a>
      ) : null;
    case "badge":
      return <Badge variant="secondary">{String(value)}</Badge>;
    default:
      return String(value);
  }
}

function compareValues(a: unknown, b: unknown, type: string, locale: string): number {
  if (a == null && b == null) return 0;
  if (a == null) return 1;
  if (b == null) return -1;

  if (type === "money") {
    const av = typeof a === "number" ? a : typeof a === "object" && a !== null && "value" in a ? (a as { value: number }).value : 0;
    const bv = typeof b === "number" ? b : typeof b === "object" && b !== null && "value" in b ? (b as { value: number }).value : 0;
    return av - bv;
  }
  if (type === "number") {
    return (Number(a) || 0) - (Number(b) || 0);
  }
  return String(a).localeCompare(String(b), locale);
}

export function DataTableRenderer({ title, columns, rows, sortable }: DisplayTable) {
  const { locale } = useTranslation();
  const [sortKey, setSortKey] = useState<string | null>(null);
  const [sortDir, setSortDir] = useState<SortDir>("asc");

  function handleSort(key: string) {
    if (!sortable) return;
    if (sortKey === key) {
      setSortDir((d) => (d === "asc" ? "desc" : "asc"));
    } else {
      setSortKey(key);
      setSortDir("asc");
    }
  }

  const sortedRows = sortKey
    ? [...rows].sort((a, b) => {
        const col = columns.find((c) => c.key === sortKey);
        const dir = sortDir === "asc" ? 1 : -1;
        return compareValues(a[sortKey], b[sortKey], col?.type ?? "text", locale) * dir;
      })
    : rows;

  return (
    <div className="space-y-2">
      {title && <h3 className="text-sm font-semibold text-foreground">{title}</h3>}

      <ScrollArea className="w-full">
        <Table>
          <TableHeader>
            <TableRow>
              {columns.map((col) => (
                <TableHead
                  key={col.key}
                  className={col.align === "right" ? "text-right" : col.align === "center" ? "text-center" : "text-left"}
                >
                  {sortable ? (
                    <Button
                      variant="ghost"
                      size="sm"
                      className="-ml-3 h-8 font-semibold"
                      onClick={() => handleSort(col.key)}
                      aria-sort={
                        sortKey === col.key
                          ? sortDir === "asc"
                            ? "ascending"
                            : "descending"
                          : undefined
                      }
                    >
                      {col.label}
                      {sortKey === col.key ? (
                        sortDir === "asc" ? (
                          <ArrowUp className="ml-1 h-3 w-3" />
                        ) : (
                          <ArrowDown className="ml-1 h-3 w-3" />
                        )
                      ) : (
                        <ArrowUpDown className="ml-1 h-3 w-3" />
                      )}
                    </Button>
                  ) : (
                    col.label
                  )}
                </TableHead>
              ))}
            </TableRow>
          </TableHeader>

          <TableBody>
            {sortedRows.map((row, ri) => (
              <TableRow key={ri}>
                {columns.map((col) => (
                  <TableCell
                    key={col.key}
                    className={col.align === "right" ? "text-right" : col.align === "center" ? "text-center" : "text-left"}
                  >
                    {renderCellValue(row[col.key], col.type, locale)}
                  </TableCell>
                ))}
              </TableRow>
            ))}
          </TableBody>
        </Table>
        <ScrollBar orientation="horizontal" />
      </ScrollArea>
    </div>
  );
}

import { memo, useEffect, useMemo, useRef, useState } from "react"
import { transform as sucraseTransform } from "sucrase"
import { SANDBOX_BOOTSTRAP } from "./react-sandbox/bootstrap.js"

// ─── Types ────────────────────────────────────────────────────────────────────

const WHITELIST_MODULES = [
  "react",
  "react-dom",
  "react-dom/client",
  "framer-motion",
  "recharts",
  "lucide-react",
] as const

type WhitelistedModule = (typeof WHITELIST_MODULES)[number]

interface ImportDecl {
  module: WhitelistedModule
  symbols: string[]
}

interface Layout {
  height?: number | "auto"
  aspectRatio?: string
  maxWidth?: number
}

export interface DisplayReactRendererProps {
  // Flattened DisplayReactSchema payload (PartRenderer spreads args as props)
  version?: "1"
  title?: string
  description?: string
  code: string
  language?: "jsx" | "tsx"
  entry?: "default"
  imports?: ImportDecl[]
  initialProps?: Record<string, unknown>
  layout?: Layout
  theme?: "light" | "dark" | "auto"
  // Sandbox bundle base — consumers can override (default: "/sandbox")
  sandboxBase?: string
}

// ─── Size limits (mirror SDK schema) ──────────────────────────────────────────

const MAX_CODE_BYTES = 8 * 1024
const MAX_PROPS_BYTES = 32 * 1024

// ─── Module-level bundle cache ────────────────────────────────────────────────

interface SandboxBundles {
  react: string
  reactDom: string
  framerMotion: string
  recharts: string
  lucideReact: string
}

const bundleCache = new Map<string, Promise<SandboxBundles>>()

function loadBundles(base: string): Promise<SandboxBundles> {
  const key = base
  const cached = bundleCache.get(key)
  if (cached) return cached
  const p = (async () => {
    const [react, reactDom, framerMotion, recharts, lucideReact] = await Promise.all([
      fetch(`${base}/react.js`).then((r) => r.text()),
      fetch(`${base}/react-dom.js`).then((r) => r.text()),
      fetch(`${base}/framer-motion.js`).then((r) => r.text()),
      fetch(`${base}/recharts.js`).then((r) => r.text()),
      fetch(`${base}/lucide-react.js`).then((r) => r.text()),
    ])
    return { react, reactDom, framerMotion, recharts, lucideReact }
  })()
  bundleCache.set(key, p)
  return p
}

// ─── Validation helpers ──────────────────────────────────────────────────────

function byteLength(s: string): number {
  return new TextEncoder().encode(s).length
}

function validatePayload(props: DisplayReactRendererProps): string | null {
  if (!props.code || typeof props.code !== "string") return "missing code"
  if (byteLength(props.code) > MAX_CODE_BYTES) return `code exceeds ${MAX_CODE_BYTES} bytes`
  if (props.initialProps) {
    try {
      const s = JSON.stringify(props.initialProps)
      if (byteLength(s) > MAX_PROPS_BYTES) return `initialProps exceeds ${MAX_PROPS_BYTES} bytes`
    } catch {
      return "initialProps not JSON-serializable"
    }
  }
  if (props.imports) {
    for (const imp of props.imports) {
      if (!WHITELIST_MODULES.includes(imp.module)) {
        return `import not in whitelist: ${imp.module}`
      }
    }
  }
  return null
}

// ─── Transpile user code ─────────────────────────────────────────────────────

function compile(code: string, language: "jsx" | "tsx"): { ok: true; code: string } | { ok: false; error: string } {
  try {
    const transforms: ("jsx" | "typescript" | "imports")[] = ["jsx", "imports"]
    if (language === "tsx") transforms.unshift("typescript")
    const out = sucraseTransform(code, {
      transforms,
      production: true,
      jsxRuntime: "classic",
    })
    return { ok: true, code: out.code }
  } catch (e) {
    return { ok: false, error: e instanceof Error ? e.message : String(e) }
  }
}

// ─── Build srcdoc ────────────────────────────────────────────────────────────

function buildSrcDoc(bundles: SandboxBundles): string {
  return `<!doctype html><html><head><meta charset="utf-8"><style>
  html,body{margin:0;padding:0;}
  body{font:14px/1.5 system-ui,-apple-system,sans-serif;padding:12px;box-sizing:border-box;}
  #root{min-height:0;}
  *{box-sizing:border-box;}
</style></head><body><div id="root"></div>
<script>${bundles.react}<\/script>
<script>${bundles.reactDom}<\/script>
<script>${bundles.framerMotion}<\/script>
<script>${bundles.recharts}<\/script>
<script>${bundles.lucideReact}<\/script>
<script>${SANDBOX_BOOTSTRAP}<\/script>
</body></html>`
}

// ─── Component ───────────────────────────────────────────────────────────────

export const DisplayReactRenderer = memo(function DisplayReactRenderer(props: DisplayReactRendererProps) {
  const {
    code,
    language = "jsx",
    initialProps,
    layout,
    theme = "auto",
    title,
    description,
    sandboxBase = "/sandbox",
  } = props

  const iframeRef = useRef<HTMLIFrameElement | null>(null)
  const [height, setHeight] = useState<number | null>(null)
  const [error, setError] = useState<string | null>(null)
  const [status, setStatus] = useState<"loading" | "ready" | "error">("loading")

  // Validate + compile once per payload
  const compiled = useMemo<{ ok: true; code: string } | { ok: false; error: string }>(() => {
    const validationError = validatePayload(props)
    if (validationError) return { ok: false, error: validationError }
    return compile(code, language)
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [code, language, JSON.stringify(props.imports), JSON.stringify(initialProps)])

  // Build + inject srcdoc once bundles are available
  useEffect(() => {
    if (compiled.ok === false) {
      setError(compiled.error)
      setStatus("error")
      return
    }
    let cancelled = false
    loadBundles(sandboxBase)
      .then((bundles) => {
        if (cancelled) return
        const iframe = iframeRef.current
        if (!iframe) return
        iframe.srcdoc = buildSrcDoc(bundles)
      })
      .catch((e) => {
        if (cancelled) return
        setError(`failed to load sandbox bundles: ${e instanceof Error ? e.message : String(e)}`)
        setStatus("error")
      })
    return () => {
      cancelled = true
    }
  }, [compiled, sandboxBase])

  // postMessage pump: wait for sandbox-boot → send compiled code. Also capture height + ready.
  useEffect(() => {
    const handler = (ev: MessageEvent) => {
      const iframe = iframeRef.current
      if (!iframe || ev.source !== iframe.contentWindow) return
      const data = ev.data as { type?: string; height?: number } | undefined
      if (!data || typeof data !== "object" || !data.type) return
      if (data.type === "sandbox-boot") {
        if (!compiled.ok) return
        iframe.contentWindow?.postMessage(
          {
            type: "sandbox-render",
            compiledCode: compiled.code,
            payload: {
              initialProps: initialProps ?? {},
              theme,
            },
          },
          "*",
        )
      } else if (data.type === "sandbox-ready") {
        setStatus("ready")
      } else if (data.type === "sandbox-height" && typeof data.height === "number") {
        if (layout?.height !== "auto" && typeof layout?.height === "number") return
        setHeight(data.height + 24) // padding from body
      }
    }
    window.addEventListener("message", handler)
    return () => window.removeEventListener("message", handler)
  }, [compiled, initialProps, theme, layout?.height])

  // Compute iframe style
  const iframeStyle: React.CSSProperties = {
    width: "100%",
    maxWidth: layout?.maxWidth ? `${layout.maxWidth}px` : undefined,
    aspectRatio: layout?.aspectRatio,
    height:
      typeof layout?.height === "number"
        ? `${layout.height}px`
        : height !== null
          ? `${height}px`
          : "120px",
    border: "1px solid var(--border, #e5e5e5)",
    borderRadius: "8px",
    display: "block",
    background: "var(--bg, #fff)",
  }

  if (error || (compiled.ok === false)) {
    const msg = error ?? (compiled.ok === false ? compiled.error : "unknown")
    return (
      <div className="rounded-lg border border-red-300 bg-red-50 text-red-900 p-3 text-xs">
        <div className="font-semibold mb-1">React sandbox error</div>
        <pre className="whitespace-pre-wrap break-words font-mono text-[11px]">{msg}</pre>
      </div>
    )
  }

  return (
    <div className="flex flex-col gap-1.5">
      {(title || description) && (
        <div className="flex flex-col gap-0.5 px-0.5">
          {title && <div className="text-sm font-semibold text-foreground">{title}</div>}
          {description && <div className="text-xs text-muted-foreground">{description}</div>}
        </div>
      )}
      <iframe
        ref={iframeRef}
        sandbox="allow-scripts"
        title={title ?? "react sandbox"}
        style={iframeStyle}
        aria-busy={status === "loading"}
      />
    </div>
  )
})

import type { DisplayFile } from "./sdk-types.js";
import {
  Download,
  File,
  FileCode,
  FileImage,
  FileMinus,
  FileText,
  FileVideo,
  Music,
} from "lucide-react";
import { Button } from "../ui/button.js";
import { Card } from "../ui/card.js";
import { useTranslation } from "../i18n/index.js";

function getFileIcon(type: string) {
  const mime = type.toLowerCase();
  if (mime.startsWith("image/")) return FileImage;
  if (mime.startsWith("video/")) return FileVideo;
  if (mime.startsWith("audio/")) return Music;
  if (mime === "application/pdf" || mime === "text/plain" || mime.includes("document")) return FileText;
  if (mime.includes("spreadsheet") || mime.includes("csv")) return FileMinus;
  if (mime.includes("javascript") || mime.includes("typescript") || mime.includes("json") || mime.includes("html") || mime.includes("css") || mime.includes("xml")) return FileCode;
  return File;
}

function formatSize(bytes: number): string {
  if (bytes < 1024) return `${bytes} B`;
  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
}

export function FileCardRenderer({ name, type, size, url }: DisplayFile) {
  const { t } = useTranslation();
  const Icon = getFileIcon(type);

  return (
    <Card className="flex items-center gap-3 p-3">
      <div className="shrink-0 text-primary">
        <Icon className="h-8 w-8" />
      </div>
      <div className="flex-1 min-w-0">
        <p className="font-medium text-sm truncate">{name}</p>
        <p className="text-xs text-muted-foreground">
          {type}{size !== undefined && ` · ${formatSize(size)}`}
        </p>
      </div>
      {url && (
        <Button variant="ghost" size="icon" asChild>
          <a href={url} download={name} aria-label={`${t("file.download")} ${name}`}>
            <Download className="h-4 w-4" />
          </a>
        </Button>
      )}
    </Card>
  );
}

import { useState } from "react";
import type { DisplayGallery } from "./sdk-types.js";
import { ZoomIn } from "lucide-react";
import { cn } from "../lib/utils.js";
import { Dialog, DialogContent, DialogTitle } from "../ui/dialog.js";
import { useTranslation } from "../i18n/index.js";

export function GalleryRenderer({ title, images }: DisplayGallery) {
  const { t } = useTranslation();
  const [lightboxIdx, setLightboxIdx] = useState<number | null>(null);

  const activeImage = lightboxIdx !== null ? images[lightboxIdx] : null;

  return (
    <div className="space-y-2">
      {title && <h3 className="text-sm font-medium text-foreground">{title}</h3>}

      <div className="grid grid-cols-2 md:grid-cols-3 gap-2">
        {images.map((img, i) => (
          <button
            key={i}
            className="relative group cursor-pointer rounded-md overflow-hidden"
            onClick={() => setLightboxIdx(i)}
            aria-label={img.alt ?? `${t("gallery.imageN")} ${i + 1}`}
          >
            <img
              src={img.url}
              alt={img.alt ?? ""}
              className="w-full h-full object-cover aspect-square"
              loading="lazy"
            />
            <div className="absolute inset-0 bg-background/50 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity">
              <ZoomIn className="h-5 w-5 text-foreground" />
            </div>
            {img.caption && (
              <p className="absolute bottom-0 left-0 right-0 text-sm text-muted-foreground bg-background/80 px-2 py-1 truncate">
                {img.caption}
              </p>
            )}
          </button>
        ))}
      </div>

      <Dialog open={lightboxIdx !== null} onOpenChange={(open) => { if (!open) setLightboxIdx(null); }}>
        <DialogContent className={cn("max-w-4xl p-0 bg-background/95")}>
          <DialogTitle className="sr-only">
            {activeImage?.alt ?? t("image.viewer")}
          </DialogTitle>
          {activeImage && (
            <div className="flex flex-col">
              <img
                src={activeImage.url}
                alt={activeImage.alt ?? ""}
                className="w-full max-h-[80vh] object-contain"
              />
              {activeImage.caption && (
                <p className="text-sm text-muted-foreground px-4 py-3">
                  {activeImage.caption}
                </p>
              )}
            </div>
          )}
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useState } from "react";
import type { DisplayImage } from "./sdk-types.js";
import { ZoomIn, ZoomOut, RotateCcw, X } from "lucide-react";
import { Dialog, DialogContent, DialogTitle } from "../ui/dialog.js";
import { Button } from "../ui/button.js";
import { cn } from "../lib/utils.js";
import { useTranslation } from "../i18n/index.js";

export function ImageViewerRenderer({ url, alt, caption, width, height }: DisplayImage) {
  const { t } = useTranslation();
  const [dialogOpen, setDialogOpen] = useState(false);
  const [zoom, setZoom] = useState(1);

  function handleOpen() {
    setZoom(1);
    setDialogOpen(true);
  }

  return (
    <div className="flex flex-col gap-1.5">
      <button
        className="relative group cursor-pointer rounded-md overflow-hidden inline-block"
        onClick={handleOpen}
        aria-label={`${t("image.enlarge")}${alt ? `: ${alt}` : ""}`}
      >
        <img
          src={url}
          alt={alt ?? ""}
          className="block max-w-full rounded-md"
          loading="lazy"
          decoding="async"
          width={width}
          height={height}
        />
        <div className="absolute inset-0 bg-background/50 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity">
          <ZoomIn className="h-5 w-5 text-foreground" />
        </div>
      </button>

      {caption && (
        <p className="text-xs text-muted-foreground">{caption}</p>
      )}

      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent className="max-w-4xl p-0 bg-background/95 overflow-hidden">
          <DialogTitle className="sr-only">{alt ?? t("image.viewer")}</DialogTitle>

          <div className="flex flex-col">
            <div className="flex items-center gap-1 p-2 border-b border-border">
              <Button
                variant="ghost"
                size="icon"
                onClick={() => setZoom((z) => Math.max(0.25, z - 0.25))}
                aria-label={t("image.zoomOut")}
                disabled={zoom <= 0.25}
              >
                <ZoomOut className="h-4 w-4" />
              </Button>

              <span className={cn("text-xs text-muted-foreground w-12 text-center tabular-nums")}>
                {Math.round(zoom * 100)}%
              </span>

              <Button
                variant="ghost"
                size="icon"
                onClick={() => setZoom((z) => Math.min(4, z + 0.25))}
                aria-label={t("image.zoomIn")}
                disabled={zoom >= 4}
              >
                <ZoomIn className="h-4 w-4" />
              </Button>

              <Button
                variant="ghost"
                size="icon"
                onClick={() => setZoom(1)}
                aria-label={t("image.resetZoom")}
              >
                <RotateCcw className="h-4 w-4" />
              </Button>

              <div className="flex-1" />

              <Button
                variant="ghost"
                size="icon"
                onClick={() => setDialogOpen(false)}
                aria-label={t("image.close")}
              >
                <X className="h-4 w-4" />
              </Button>
            </div>

            <div className="overflow-auto max-h-[80vh] flex items-center justify-center p-4">
              <img
                src={url}
                alt={alt ?? ""}
                style={{ transform: `scale(${zoom})`, transformOrigin: "center" }}
                className="max-w-full transition-transform"
                width={width}
                height={height}
              />
            </div>

            {caption && (
              <p className="text-xs text-muted-foreground text-center p-2 border-t border-border">
                {caption}
              </p>
            )}
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useState } from "react";
import type { DisplayLink } from "./sdk-types.js";
import { Globe } from "lucide-react";
import { Card } from "../ui/card";

function getDomain(url: string, domainProp?: string): string {
  if (domainProp) return domainProp;
  try {
    return new URL(url).hostname.replace(/^www\./, "");
  } catch {
    return url;
  }
}

export function LinkPreviewRenderer({
  url,
  title,
  description,
  image,
  favicon,
  domain,
}: DisplayLink) {
  const [imgError, setImgError] = useState(false);
  const [faviconError, setFaviconError] = useState(false);

  const displayDomain = getDomain(url, domain);

  return (
    <a
      href={url}
      target="_blank"
      rel="noopener noreferrer"
      aria-label={`Link: ${title}`}
    >
      <Card className="overflow-hidden hover:bg-muted/50 transition-colors">
