// Converte SDKMessage[] (formato do backbone JSONL) em Message[] (formato do chat UI).
// Usado pelo transport.getMessages (batch) e pelo useOpenClaudeChat (streaming).

import type { Message, MessagePart, ToolInvocationPart, TurnMetadata } from "../types.js";

// ── SDK types (espelho minimo, sem dep dura) ────────────────────────

export interface TextBlock {
  type: "text";
  text: string;
}

export interface ThinkingBlock {
  type: "thinking";
  thinking: string;
}

export interface ToolUseBlock {
  type: "tool_use";
  id: string;
  name: string;
  input: Record<string, unknown>;
}

export interface ToolResultBlock {
  type: "tool_result";
  tool_use_id: string;
  content: unknown;
  is_error?: boolean;
}

export type ContentBlock = TextBlock | ThinkingBlock | ToolUseBlock | ToolResultBlock;

export interface SDKAssistantMessage {
  type: "assistant";
  uuid: string;
  session_id: string;
  message: {
    id: string;
    content: ContentBlock[];
    model?: string;
    stop_reason?: string;
    usage?: {
      input_tokens?: number;
      output_tokens?: number;
      cache_read_input_tokens?: number;
    };
  };
  parent_tool_use_id: string | null;
  error?: { type: string; message: string };
  isSynthetic?: boolean;
}

export interface SDKUserMessage {
  type: "user";
  session_id: string;
  message: { content: ContentBlock[] | unknown };
  parent_tool_use_id: string | null;
  isSynthetic?: boolean;
}

export interface SDKResultMessage {
  type: "result";
  subtype?: string;
  session_id: string;
  total_cost_usd?: number;
  duration_ms?: number;
  is_error?: boolean;
  num_turns?: number;
  usage?: {
    input_tokens?: number;
    output_tokens?: number;
    cache_read_input_tokens?: number;
  };
  errors?: Array<{ message: string }>;
  permission_denials?: Array<{ tool: string; reason?: string }>;
}

export interface SDKSystemMessage {
  type: "system";
  subtype?: string;
  session_id: string;
  [k: string]: unknown;
}

export type SDKMessage =
  | SDKAssistantMessage
  | SDKUserMessage
  | SDKResultMessage
  | SDKSystemMessage
  | { type: string; [k: string]: unknown };

// ── Helpers ─────────────────────────────────────────────────────────

export function extractTextFromParts(parts: MessagePart[]): string {
  return parts
    .filter((p): p is { type: "text"; text: string } => p.type === "text")
    .map((p) => p.text)
    .join("\n");
}

let _seqId = 0;
function seqId(prefix: string): string {
  return `${prefix}-${++_seqId}-${Math.random().toString(36).slice(2, 6)}`;
}

// ── Batch converter (history) ───────────────────────────────────────

/**
 * Converte um array de SDKMessage (como armazenado no JSONL do backbone)
 * em Message[] prontas para o chat UI.
 *
 * Logica:
 * - SDKAssistantMessage(s) contiguos → acumula parts na mesma Message assistant
 * - SDKUserMessage com tool_result → atualiza ToolInvocationPart do assistant anterior
 * - SDKUserMessage com text (prompt do usuario) → nova Message user
 * - SDKResultMessage → attach TurnMetadata na ultima Message assistant
 * - isSynthetic → marca mas nao filtra (consumer decide)
 */
export function convertSDKMessages(sdkMessages: SDKMessage[]): Message[] {
  const result: Message[] = [];
  let currentAssistant: Message | null = null;
  const toolPartByCallId = new Map<string, ToolInvocationPart>();

  function finalizeAssistant() {
    if (currentAssistant) {
      // Settle any pending tool calls
      for (const part of currentAssistant.parts) {
        if (part.type === "tool-invocation") {
          const tip = part as ToolInvocationPart;
          if (tip.toolInvocation.state === "call" || tip.toolInvocation.state === "partial-call") {
            tip.toolInvocation = { ...tip.toolInvocation, state: "result", result: null };
          }
        }
      }
      currentAssistant.content = extractTextFromParts(currentAssistant.parts);
      currentAssistant = null;
    }
    toolPartByCallId.clear();
  }

  for (const msg of sdkMessages) {
    if (msg.type === "assistant") {
      const sdk = msg as SDKAssistantMessage;

      // Skip synthetic messages
      if (sdk.isSynthetic) continue;

      // Se nao tem parent_tool_use_id, e uma nova "rodada" do assistant.
      // Se tem, e continuacao (apos tool result). Ambos acumulam no mesmo Message.
      if (!currentAssistant) {
        currentAssistant = {
          id: sdk.uuid || seqId("asst"),
          role: "assistant",
          content: "",
          parts: [],
        };
        result.push(currentAssistant);
      }

      // Extract error from SDK message
      if (sdk.error) {
        currentAssistant.parts.push({
          type: "text",
          text: `⚠️ **${sdk.error.type}**: ${sdk.error.message}`,
        });
      }

      // Store model info for metadata
      if (sdk.message?.model) {
        currentAssistant.turnMeta = {
          ...currentAssistant.turnMeta,
          model: sdk.message.model,
        };
      }

      const blocks = sdk.message?.content ?? [];
      for (const block of blocks) {
        if (block.type === "text") {
          currentAssistant.parts.push({ type: "text", text: (block as TextBlock).text });
        } else if (block.type === "thinking") {
          currentAssistant.parts.push({ type: "reasoning", reasoning: (block as ThinkingBlock).thinking });
        } else if (block.type === "tool_use") {
          const tb = block as ToolUseBlock;
          if (toolPartByCallId.has(tb.id)) continue;
          const part: ToolInvocationPart = {
            type: "tool-invocation",
            toolInvocation: {
              toolName: tb.name,
              toolCallId: tb.id,
              state: "call",
              args: tb.input,
            },
          };
          toolPartByCallId.set(tb.id, part);
          currentAssistant.parts.push(part);
        }
      }
      continue;
    }

    if (msg.type === "user") {
      const sdk = msg as SDKUserMessage;

      // Skip synthetic
      if (sdk.isSynthetic) continue;

      const content = sdk.message?.content;

      // Check if this is a tool_result message or a real user message
      if (Array.isArray(content)) {
        const blocks = content as ContentBlock[];
        const hasToolResult = blocks.some((b) => b.type === "tool_result");

        if (hasToolResult && currentAssistant) {
          // Tool results — update existing tool parts
          for (const block of blocks) {
            if (block.type === "tool_result") {
              const tr = block as ToolResultBlock;
              const part = toolPartByCallId.get(tr.tool_use_id);
              if (part) {
                part.toolInvocation = {
                  ...part.toolInvocation,
                  state: "result",
                  result: tr.content,
                  isError: tr.is_error,
                };
              }
            }
          }
          continue;
        }

        // Real user message with text
        const textBlocks = blocks.filter((b): b is TextBlock => b.type === "text");
        if (textBlocks.length > 0) {
          finalizeAssistant();
          const text = textBlocks.map((b) => b.text).join("\n");
          result.push({
            id: seqId("user"),
            role: "user",
            content: text,
            parts: textBlocks.map((b) => ({ type: "text" as const, text: b.text })),
          });
          continue;
        }
      }

      // Simple string content (user prompt)
      if (typeof content === "string" && content.trim()) {
        finalizeAssistant();
        result.push({
          id: seqId("user"),
          role: "user",
          content: content,
          parts: [{ type: "text", text: content }],
        });
        continue;
      }

      // User message without identifiable content — skip
      continue;
    }

    if (msg.type === "result") {
      const sdk = msg as SDKResultMessage;
      // Attach metadata to the last assistant message
      if (currentAssistant) {
        const meta: TurnMetadata = {
          ...currentAssistant.turnMeta,
          costUsd: sdk.total_cost_usd,
          durationMs: sdk.duration_ms,
          numTurns: sdk.num_turns,
          isError: sdk.is_error,
          errors: sdk.errors,
        };
        if (sdk.usage) {
          meta.inputTokens = sdk.usage.input_tokens;
          meta.outputTokens = sdk.usage.output_tokens;
          meta.cachedTokens = sdk.usage.cache_read_input_tokens;
        }
        currentAssistant.turnMeta = meta;
      }
      finalizeAssistant();
      continue;
    }

    // Other types (system, etc.) — ignored for now
  }

  // Finalize any remaining assistant message
  finalizeAssistant();

  return result;
}

import { clsx, type ClassValue } from "clsx";
import { twMerge } from "tailwind-merge";

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

import React from "react";
import { AlertTriangle } from "lucide-react";
import { useTranslation } from "../i18n/index.js";

interface State {
  hasError: boolean;
  message?: string;
}

interface Props {
  children: React.ReactNode;
  label?: string;
}

/**
 * Isola o crash de um renderer (ex: display widget com input invalido) pra
 * evitar que um unico bloco derrube a arvore React inteira. O chat continua
 * renderizando os outros parts, e no lugar do part quebrado mostra um aviso.
 */
export class PartErrorBoundary extends React.Component<Props, State> {
  state: State = { hasError: false };

  static getDerivedStateFromError(error: unknown): State {
    return {
      hasError: true,
      message: error instanceof Error ? error.message : String(error),
    };
  }

  componentDidCatch(error: unknown, info: unknown) {
    // eslint-disable-next-line no-console
    console.warn("[openclaude-chat] part renderer failed:", error, info);
  }

  render() {
    if (this.state.hasError) {
      return (
        <ErrorFallback label={this.props.label} message={this.state.message} />
      );
    }
    return this.props.children;
  }
}

function ErrorFallback({ label, message }: { label?: string; message?: string }) {
  const { t } = useTranslation();
  return (
    <div
      role="alert"
      className="flex items-start gap-2 rounded-md border border-destructive/30 bg-destructive/5 px-3 py-2 text-xs text-destructive"
    >
      <AlertTriangle className="size-3.5 shrink-0 mt-0.5" />
      <span className="flex-1 min-w-0 break-words font-mono">
        {label ? `[${label}] ` : ""}
        {message ?? t("partError.default")}
      </span>
    </div>
  );
}

import { memo, useState } from "react";
import { Paperclip, ChevronDown } from "lucide-react";
import { Markdown } from "../components/Markdown.js";
import { LazyRender } from "../components/LazyRender.js";
import { ReasoningBlock } from "./ReasoningBlock.js";
import { ToolActivity } from "./ToolActivity.js";
import { ToolResult } from "./ToolResult.js";
import { TaskCard, type TaskCardProps } from "./TaskCard.js";
import { resolveDisplayRenderer } from "../display/registry.js";
import type { DisplayRendererMap } from "../display/registry.js";
import { Collapsible, CollapsibleTrigger, CollapsibleContent } from "../ui/collapsible.js";
import { cn } from "../lib/utils.js";
import { useTranslation } from "../i18n/index.js";
import type { MessagePart, TextPart, ReasoningPart, ToolInvocationPart } from "../types.js";

const HEAVY_RENDERERS = new Set([
  "chart", "map", "table",
  "spreadsheet", "gallery", "image",
]);

export interface PartRendererProps {
  part: MessagePart;
  isStreaming?: boolean;
  displayRenderers?: DisplayRendererMap;
}

// ─── Attachment sub-components ────────────────────────────────────────────────

function AttachmentTextBlock({ filename, content }: { filename: string; content: string }) {
  const { t } = useTranslation();
  const [open, setOpen] = useState(false);
  const lines = content.split("\n");
  const preview = lines.slice(0, 3).join("\n") + (lines.length > 3 && !open ? "\n…" : "");

  return (
    <Collapsible open={open} onOpenChange={setOpen} className="rounded-lg border text-xs overflow-hidden">
      <div className="flex items-center gap-2 px-3 py-2 bg-muted/50 border-b">
        <Paperclip className="h-3.5 w-3.5 shrink-0 text-muted-foreground" />
        <span className="flex-1 truncate font-medium">{filename}</span>
        <CollapsibleTrigger asChild>
          <button type="button" className="text-muted-foreground hover:text-foreground transition-colors" aria-label={open ? t("part.collapse") : t("part.expand")}>
            <ChevronDown className={cn("h-3.5 w-3.5 transition-transform", open && "rotate-180")} />
          </button>
        </CollapsibleTrigger>
      </div>
      <pre className="px-3 py-2 text-muted-foreground whitespace-pre-wrap break-words">{preview}</pre>
      <CollapsibleContent>
        <pre className="px-3 py-2 max-h-40 overflow-auto whitespace-pre-wrap break-words border-t">{content}</pre>
      </CollapsibleContent>
    </Collapsible>
  );
}

// ─── Main renderer ────────────────────────────────────────────────────────────

export const PartRenderer = memo(function PartRenderer({ part, isStreaming, displayRenderers }: PartRendererProps) {
  switch (part.type) {
    case "text": {
      const p = part as TextPart;
      if (p.text.startsWith("[📎")) {
        const firstNewline = p.text.indexOf("\n");
        const header = firstNewline >= 0 ? p.text.slice(0, firstNewline) : p.text;
        const body = firstNewline >= 0 ? p.text.slice(firstNewline + 1) : "";
        const match = header.match(/^\[📎\s+(.+?)\]?$/);
        const filename = match?.[1] ?? header;
        return <AttachmentTextBlock filename={filename} content={body} />;
      }
      return <Markdown>{p.text}</Markdown>;
    }

    case "reasoning": {
      const p = part as ReasoningPart;
      return <ReasoningBlock content={p.reasoning} isStreaming={isStreaming} />;
    }

    case "tool-invocation": {
      const { toolInvocation } = part as ToolInvocationPart;
      // O openclaude-sdk entrega os display tools como meta-tools MCP com
      // prefixo `mcp__display__display_*` (ex: mcp__display__display_highlight).
      // O tipo especifico do widget vem no campo `action` do input/args
      // (ex: {action: "metric", label: "...", value: "..."}).
      //
      // Alem disso aceitamos a forma "legada" direta `display_*` (compat).
      const name = toolInvocation.toolName;
      const isMcpDisplay = /^mcp__display__display_(highlight|collection|card|visual)$/.test(name);
      const isLegacyDisplay = name.startsWith("display_");
      const isDisplay = isMcpDisplay || isLegacyDisplay;

      if (isDisplay) {
        // IMPORTANTE: para display tools, o `args` (input) contem a definicao
        // COMPLETA do widget. O `result` (tool_result) e apenas uma confirmacao
        // minima (`{action: "metric"}`). Sempre preferimos args aqui.
        const payload = toolInvocation.args as Record<string, unknown> | undefined;
        // Para meta-tools MCP, a action vem no payload.
        // Para display_* legado, a action e o sufixo do toolName.
        const action = isMcpDisplay
          ? (payload?.action as string | undefined)
          : name.replace(/^display_/, "");
        const Renderer = action ? resolveDisplayRenderer(action, displayRenderers) : null;
        if (payload && Renderer && action) {
          // Alguns campos complexos (ex: trend, data) podem chegar serializados
          // como JSON string se o modelo nao souber passar objetos. Tentamos
          // parsear string → objeto antes de spreadar no renderer.
          const normalized: Record<string, unknown> = {};
          for (const [k, v] of Object.entries(payload)) {
            if (typeof v === "string" && (v.startsWith("{") || v.startsWith("["))) {
              try {
                normalized[k] = JSON.parse(v);
              } catch {
                normalized[k] = v;
              }
            } else {
              normalized[k] = v;
            }
          }
          // key by toolCallId so iframe-based renderers (DisplayReactRenderer)
          // unmount/remount cleanly when a new tool_use block arrives.
          const rendered = <Renderer key={toolInvocation.toolCallId} {...normalized} />;
          // NOTE: LazyRender via IntersectionObserver nao funciona bem dentro
          // do virtualized MessageList (itens ficam position:absolute e o
          // observer nao dispara consistente). Renderizamos direto.
          return rendered;
        }
      }

      if (toolInvocation.state === "result") {
        if (toolInvocation.result != null) {
          return (
            <ToolResult
              toolName={toolInvocation.toolName}
              result={toolInvocation.result}
              isError={toolInvocation.isError}
            />
          );
        }
        return (
          <ToolActivity
            toolName={toolInvocation.toolName}
            state="result"
            args={toolInvocation.args}
          />
        );
      }

      return (
        <ToolActivity
          toolName={toolInvocation.toolName}
          state={toolInvocation.state}
          args={toolInvocation.args}
        />
      );
    }

    case "task-card": {
      const p = part as unknown as TaskCardProps;
      return <TaskCard {...p} />;
    }

    default:
      return null;
  }
});

import { useEffect, useState } from "react";
import { Brain, ChevronDown, ChevronRight } from "lucide-react";
import { Collapsible, CollapsibleContent, CollapsibleTrigger } from "../ui/collapsible.js";

export interface ReasoningBlockProps {
  content: string;
  isStreaming?: boolean;
  className?: string;
}

export function ReasoningBlock({ content, isStreaming = false, className }: ReasoningBlockProps) {
  const [expanded, setExpanded] = useState(isStreaming);

  useEffect(() => {
    if (isStreaming) {
      setExpanded(true);
    } else {
      setExpanded(false);
    }
  }, [isStreaming]);

  return (
    <Collapsible open={expanded} onOpenChange={setExpanded} className={className}>
      <div className="border border-border bg-muted/30 rounded-md text-sm overflow-hidden">
        <CollapsibleTrigger className="flex items-center gap-2 px-3 py-2 w-full text-left font-medium text-muted-foreground hover:bg-muted/60 cursor-pointer">
          <Brain className="h-3.5 w-3.5" aria-hidden="true" />
          <span className="font-mono text-xs">reasoning</span>
          {expanded
            ? <ChevronDown className="h-3.5 w-3.5 ml-auto" aria-hidden="true" />
            : <ChevronRight className="h-3.5 w-3.5 ml-auto" aria-hidden="true" />
          }
        </CollapsibleTrigger>
        <CollapsibleContent>
          <div className="max-h-96 overflow-y-auto px-3 py-3 text-muted-foreground whitespace-pre-wrap break-words border-t border-border text-xs">
            {content}
          </div>
        </CollapsibleContent>
      </div>
    </Collapsible>
  );
}

import { Check, X, Loader2, Square, FileText } from "lucide-react";
import { cn } from "../lib/utils.js";

export type TaskStatus = "in_progress" | "completed" | "failed" | "stopped";

export interface TaskCardProps {
  description: string;
  status: TaskStatus;
  summary?: string;
  toolUses?: number;
  totalTokens?: number;
  outputFile?: string;
  className?: string;
}

const statusConfig: Record<TaskStatus, { icon: typeof Loader2; label: string; color: string }> = {
  in_progress: { icon: Loader2, label: "In Progress", color: "text-blue-500" },
  completed: { icon: Check, label: "Completed", color: "text-green-500" },
  failed: { icon: X, label: "Failed", color: "text-red-500" },
  stopped: { icon: Square, label: "Stopped", color: "text-muted-foreground" },
};

export function TaskCard({ description, status, summary, toolUses, totalTokens, outputFile, className }: TaskCardProps) {
  const config = statusConfig[status];
  const Icon = config.icon;

  return (
    <div className={cn(
      "rounded-lg border bg-muted/30 px-4 py-3 text-sm",
      className,
    )}>
      <div className="flex items-center gap-2">
        <Icon
          size={14}
          className={cn(config.color, status === "in_progress" && "animate-spin")}
        />
        <span className={cn("text-xs font-medium", config.color)}>{config.label}</span>
      </div>
      <p className="mt-1 text-foreground">{description}</p>

      {summary && (
        <p className="mt-2 text-xs text-muted-foreground">{summary}</p>
      )}

      {(toolUses != null || totalTokens != null) && (
        <div className="flex items-center gap-3 mt-2 text-[10px] text-muted-foreground">
          {toolUses != null && <span>{toolUses} tool calls</span>}
          {totalTokens != null && <span>{(totalTokens / 1000).toFixed(1)}k tokens</span>}
        </div>
      )}

      {outputFile && (
        <div className="flex items-center gap-1.5 mt-2 text-xs text-muted-foreground">
          <FileText size={12} />
          <span className="font-mono truncate">{outputFile}</span>
        </div>
      )}
    </div>
  );
}

import { Check, Download, FileText, FilePlus, FolderSearch, Globe, Loader2, Pencil, Search, Terminal, Wrench, type LucideIcon } from "lucide-react";
import { cn } from "../lib/utils.js";
import { useTranslation } from "../i18n/index.js";

export type ToolActivityState = "call" | "partial-call" | "result";

export interface ToolActivityProps {
  toolName: string;
  state: ToolActivityState;
  args?: Record<string, unknown>;
  className?: string;
  iconMap?: Partial<Record<string, LucideIcon>>;
}

export const defaultToolIconMap: Record<string, LucideIcon> = {
  WebSearch: Globe,
  Bash: Terminal,
  Read: FileText,
  Edit: Pencil,
  Write: FilePlus,
  Grep: Search,
  Glob: FolderSearch,
  WebFetch: Download,
  ListDir: FolderSearch,
};

function formatToolName(name: string): string {
  return name
    .replace(/_/g, " ")
    .replace(/([a-z])([A-Z])/g, "$1 $2")
    .replace(/\b\w/g, (c) => c.toUpperCase());
}

function resolveIcon(toolName: string, iconMap: Record<string, LucideIcon | undefined>): LucideIcon {
  return iconMap[toolName] ?? Wrench;
}

function formatArgs(toolName: string, args?: Record<string, unknown>): string | null {
  if (!args) return null;
  if (toolName === "Bash" && args.command) return String(args.command);
  if (toolName === "Read" && args.path) return String(args.path);
  if (toolName === "Edit" && args.file_path) return String(args.file_path);
  if (toolName === "Write" && args.file_path) return String(args.file_path);
  if (toolName === "Grep" && args.pattern) return String(args.pattern);
  if (toolName === "Glob" && args.pattern) return String(args.pattern);
  if (toolName === "WebSearch" && args.query) return String(args.query);
  if (toolName === "ListDir" && args.path) return String(args.path);
  return null;
}

export function ToolActivity({ toolName, state, args, className, iconMap }: ToolActivityProps) {
  const { t } = useTranslation();
  const mergedIconMap = iconMap ? { ...defaultToolIconMap, ...iconMap } : defaultToolIconMap;
  const Icon = resolveIcon(toolName, mergedIconMap);
  const isActive = state === "call" || state === "partial-call";
  const displayName = formatToolName(toolName);
  const argsPreview = formatArgs(toolName, args);
  const elapsedMs = args?._elapsedMs as number | undefined;

  return (
    <div className={cn(
      "flex items-center gap-2 rounded-md border border-border bg-muted/40 px-3 py-2 text-sm",
      className
    )}>
      <span className="text-muted-foreground shrink-0" aria-hidden="true">
        <Icon size={14} />
      </span>
      <span className="font-medium font-mono text-foreground">{displayName}</span>
      {argsPreview && (
        <span className="truncate text-xs text-muted-foreground font-mono max-w-[300px]">{argsPreview}</span>
      )}
      {isActive && elapsedMs != null && elapsedMs > 0 && (
        <span className="text-[10px] text-muted-foreground tabular-nums">
          {(elapsedMs / 1000).toFixed(1)}s
        </span>
      )}
      <span className="ml-auto text-muted-foreground">
        {isActive ? (
          <Loader2 size={14} className="animate-spin" aria-label={t("tool.running")} />
        ) : (
          <Check size={14} aria-label={t("tool.done")} />
        )}
      </span>
    </div>
  );
}

import { AlertCircle, CheckCircle, ChevronDown, ChevronRight } from "lucide-react";
import { useState } from "react";
import { Collapsible, CollapsibleContent, CollapsibleTrigger } from "../ui/collapsible.js";
import { cn } from "../lib/utils.js";

export interface ToolResultProps {
  toolName: string;
  result: unknown;
  isError?: boolean;
  className?: string;
}

function serializeResult(result: unknown): string {
  try {
    if (typeof result === "object" && result !== null && "value" in (result as Record<string, unknown>)) {
      return String((result as Record<string, unknown>).value);
    }
    return JSON.stringify(result, null, 2);
  } catch {
    return String(result);
  }
}

function extractPreview(result: unknown): string | null {
  if (typeof result === "string") return result.length > 120 ? result.slice(0, 120) + "..." : result;
  if (typeof result === "object" && result !== null) {
    const r = result as Record<string, unknown>;
    if (typeof r.value === "string") {
      const v = r.value as string;
      return v.length > 120 ? v.slice(0, 120) + "..." : v;
    }
  }
  return null;
}

export function ToolResult({ toolName, result, isError = false, className }: ToolResultProps) {
  const [expanded, setExpanded] = useState(false);
  const serialized = serializeResult(result);
  const preview = extractPreview(result);

  return (
    <Collapsible open={expanded} onOpenChange={setExpanded} className={className}>
      <div className={cn(
        "rounded-md border text-sm overflow-hidden",
        isError
          ? "border-destructive/40 bg-destructive/5"
          : "border-border bg-muted/40"
      )}>
        <CollapsibleTrigger
          className={cn(
            "flex items-center gap-2 w-full px-3 py-2 text-left font-medium hover:bg-muted/60 cursor-pointer",
          )}
          aria-expanded={expanded}
        >
          {isError ? (
            <AlertCircle className="h-3.5 w-3.5 shrink-0 text-destructive" aria-hidden="true" />
          ) : (
            <CheckCircle className="h-3.5 w-3.5 shrink-0 text-muted-foreground" aria-hidden="true" />
          )}
          <span className={cn("font-mono text-xs", isError ? "text-destructive" : "text-foreground")}>
            {isError ? `${toolName} erro` : `${toolName} ok`}
          </span>
          {!expanded && preview && (
            <span className="truncate text-xs text-muted-foreground font-mono max-w-[400px] ml-1">{preview}</span>
          )}
          {expanded
            ? <ChevronDown className="h-3.5 w-3.5 shrink-0 text-muted-foreground ml-auto" aria-hidden="true" />
            : <ChevronRight className="h-3.5 w-3.5 shrink-0 text-muted-foreground ml-auto" aria-hidden="true" />
          }
        </CollapsibleTrigger>
        <CollapsibleContent>
          <pre className="max-h-80 overflow-y-auto p-3 font-mono text-xs whitespace-pre-wrap break-all bg-muted/30 border-t border-border">
            {serialized}
          </pre>
        </CollapsibleContent>
      </div>
    </Collapsible>
  );
}

// Transport layer — abstrai a comunicacao HTTP dos componentes.
// Componentes nunca chamam fetch diretamente; usam um ChatTransport.

import type { Conversation } from "./components/history/types.js"
import type { Message } from "./types.js"

// ── Tipos auxiliares ─────────────────────────────────────────────────────

export interface ConversationDetail extends Conversation {
  agentId?: string
}

export interface GetMessagesParams {
  /** Max messages to return. Default: 50, max: 200. */
  limit?: number
  /** Cursor — return messages before this point. Omit for latest messages. */
  before?: string
}

export interface GetMessagesResult {
  messages: Message[]
  /** true if there are older messages available. */
  hasMore: boolean
  /** Cursor for the next page (null if no more). */
  cursor: string | null
}

// ── Interface principal ──────────────────────────────────────────────────

export interface ChatTransport {
  // --- Conversas (History, TopBar) ---
  listConversations(params?: { agentId?: string }): Promise<Conversation[]>
  createConversation(params?: {
    agentId?: string
    options?: Record<string, unknown>
  }): Promise<{ sessionId: string }>
  getConversation(id: string): Promise<ConversationDetail>
  updateConversation(id: string, data: { title?: string; starred?: boolean }): Promise<void>
  deleteConversation(id: string): Promise<void>
  exportConversation(id: string, format?: "json" | "markdown"): Promise<Blob>

  // --- Mensagens (Chat) ---
  getMessages(conversationId: string, params?: GetMessagesParams): Promise<GetMessagesResult>
  sendMessage(
    conversationId: string,
    params: { content: string; attachments?: File[] },
  ): AsyncGenerator<unknown> | ReadableStream<unknown>
  getAttachmentUrl(conversationId: string, file: string): string
}

// ── Transport default (fetch) ────────────────────────────────────────────

export function createDefaultTransport(endpoint: string, token?: string): ChatTransport {
  const baseHeaders: Record<string, string> = {
    "Content-Type": "application/json",
  }
  if (token) baseHeaders["Authorization"] = `Bearer ${token}`

  async function request(method: string, path: string, body?: unknown): Promise<Response> {
    const res = await fetch(`${endpoint}${path}`, {
      method,
      headers: baseHeaders,
      body: body ? JSON.stringify(body) : undefined,
    })
    if (!res.ok) {
      const errText = await res.text().catch(() => `HTTP ${res.status}`)
      throw new Error(`${method} ${path}: ${res.status} — ${errText}`)
    }
    return res
  }

  return {
    async listConversations(params) {
      const qs = params?.agentId ? `?agentId=${encodeURIComponent(params.agentId)}` : ""
      const res = await request("GET", `/conversations${qs}`)
      return res.json()
    },

    async createConversation(params) {
      const res = await request("POST", "/conversations", params)
      return res.json()
    },

    async getConversation(id) {
      const res = await request("GET", `/conversations/${encodeURIComponent(id)}`)
      return res.json()
    },

    async updateConversation(id, data) {
      await request("PATCH", `/conversations/${encodeURIComponent(id)}`, data)
    },

    async deleteConversation(id) {
      await request("DELETE", `/conversations/${encodeURIComponent(id)}`)
    },

    async exportConversation(id, format = "json") {
      const res = await request(
        "GET",
        `/conversations/${encodeURIComponent(id)}/export?format=${format}`,
      )
      return res.blob()
    },

    async getMessages(id, params) {
      const qs = new URLSearchParams()
      if (params?.limit) qs.set("limit", String(params.limit))
      if (params?.before) qs.set("before", params.before)
      const qsStr = qs.toString()
      const res = await request("GET", `/conversations/${encodeURIComponent(id)}/messages${qsStr ? `?${qsStr}` : ""}`)
      return res.json()
    },

    async *sendMessage(id, params) {
      const res = await fetch(`${endpoint}/conversations/${encodeURIComponent(id)}/messages`, {
        method: "POST",
        headers: { ...baseHeaders, Accept: "text/event-stream" },
        body: JSON.stringify({ message: params.content }),
      })
      if (!res.ok || !res.body) {
        const errText = await res.text().catch(() => `HTTP ${res.status}`)
        throw new Error(`POST /conversations/${id}/messages: ${res.status} — ${errText}`)
      }
      // Yield the ReadableStream body — the consumer (useOpenClaudeChat) handles SSE parsing
      yield res.body
    },

    getAttachmentUrl(id, file) {
      const tokenQs = token ? `?token=${encodeURIComponent(token)}` : ""
      return `${endpoint}/conversations/${encodeURIComponent(id)}/attachments/${encodeURIComponent(file)}${tokenQs}`
    },
  }
}

// Tipos locais usados pelo @codrstudio/openclaude-chat.
// Nao depende de @ai-sdk/react. Modelo inspirado nos "parts" do ai-sdk,
// mas alimentado a partir de SDKMessage do @codrstudio/openclaude-sdk.

export type TextPart = { type: "text"; text: string };

export type ReasoningPart = { type: "reasoning"; reasoning: string };

export type ToolInvocationState = "call" | "partial-call" | "result";

export type ToolInvocationPart = {
  type: "tool-invocation";
  toolInvocation: {
    toolName: string;
    toolCallId: string;
    state: ToolInvocationState;
    args?: Record<string, unknown>;
    result?: unknown;
    isError?: boolean;
  };
};

export type ImageAttachmentPart = { type: "image"; _ref?: string; mimeType?: string };
export type FileAttachmentPart = { type: "file"; _ref?: string; mimeType?: string };

export type MessagePart =
  | TextPart
  | ReasoningPart
  | ToolInvocationPart
  | ImageAttachmentPart
  | FileAttachmentPart
  | { type: string };

export type MessageRole = "user" | "assistant";

/** Metadata de custo/usage de um turno, extraida do SDKResultMessage. */
export interface TurnMetadata {
  costUsd?: number;
  durationMs?: number;
  numTurns?: number;
  inputTokens?: number;
  outputTokens?: number;
  cachedTokens?: number;
  model?: string;
  stopReason?: string;
  isError?: boolean;
  errors?: Array<{ message: string }>;
}

export interface Message {
  id: string;
  role: MessageRole;
  content: string;
  parts: MessagePart[];
  /** Metadata do turno — presente na ultima mensagem assistant do turno. */
  turnMeta?: TurnMetadata;
  /** Flag de mensagem sintetica (replay de sessao resumida). */
  isSynthetic?: boolean;
}

